import React, { memo, useState } from 'react';
import { DiscoveryStarRating } from './DiscoveryStarRating.js';

export interface ReviewInsightsToggleProps {
    rating?: number;
    reviewCount?: number;
    summary?: string;
    likes?: string[];
    className?: string;
    productName?: string;
    productSku?: string;
    onToggle?: (data: { productName?: string; productSku?: string; action: 'expand' | 'collapse' }) => void;
}

const ChevronIcon = ({ isExpanded }: { isExpanded: boolean }) => (
    <svg
        width="16"
        height="16"
        viewBox="0 0 20 20"
        fill="currentColor"
        style={{
            transform: isExpanded ? 'rotate(180deg)' : 'rotate(0deg)',
            transition: 'transform 0.2s ease',
        }}
    >
        <path
            fillRule="evenodd"
            d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z"
            clipRule="evenodd"
        />
    </svg>
);

export const ReviewInsightsToggle = memo(function ReviewInsightsToggle({
    rating = 0,
    reviewCount = 0,
    summary,
    likes,
    className,
    productName,
    productSku,
    onToggle,
}: ReviewInsightsToggleProps): JSX.Element {
    const [isExpanded, setIsExpanded] = useState(false);
    const hasInsights = summary || (likes && likes.length > 0);

    const handleToggle = (e: React.MouseEvent) => {
        e.stopPropagation();
        const action = isExpanded ? 'collapse' : 'expand';
        onToggle?.({ productName, productSku, action });
        setIsExpanded(!isExpanded);
    };

    return (
        <div className={`omniguide-pr-review-insights ${className || ''}`}>
            <div className="omniguide-pr-review-insights__rating-row">
                <DiscoveryStarRating rating={rating} reviewCount={reviewCount} />
                {hasInsights && (
                    <button
                        type="button"
                        onClick={handleToggle}
                        className="omniguide-pr-review-insights__chevron-btn"
                        aria-label={isExpanded ? 'Hide review insights' : 'Show review insights'}
                        aria-expanded={isExpanded}
                    >
                        <ChevronIcon isExpanded={isExpanded} />
                    </button>
                )}
            </div>

            {isExpanded && hasInsights && (
                <div className="omniguide-pr-review-insights__panel">
                    {summary && (
                        <div className="omniguide-pr-review-insights__section">
                            <h5 className="omniguide-pr-review-insights__title">Customers Say</h5>
                            <p className="omniguide-pr-review-insights__summary">{summary}</p>
                        </div>
                    )}
                    {likes && likes.length > 0 && (
                        <div className="omniguide-pr-review-insights__section">
                            <h5 className="omniguide-pr-review-insights__title">Customers Like</h5>
                            <ul className="omniguide-pr-review-insights__likes-list">
                                {likes.map((like, index) => (
                                    <li key={index} className="omniguide-pr-review-insights__like-item">
                                        <span className="omniguide-pr-review-insights__like-bullet">&bull;</span>
                                        <span>{like}</span>
                                    </li>
                                ))}
                            </ul>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
});
