/**
 * REST response normalizers — pure mapping functions.
 *
 * Data flow: fetch raw → normalize() → zod.parse(normalized) → return public DTO
 *
 * Backend field aliases (question vs question_text, answers vs options)
 * resolve here, before validation touches them.
 */

import type {
  RawSessionResponse,
  RawQuestionsResponse,
  RawFeedbackResponse,
} from './types.js';
import type { DiscoveryQuestion } from '../../types.js';

// ── Session ─────────────────────────────────────────────────────

export interface NormalizedSessionResponse {
  sessionId: string;
  welcomeText?: string;
  seedQuestions?: string[];
  aiDisabled?: boolean;
  disabledReason?: string | null;
}

export function normalizeSessionResponse(raw: RawSessionResponse): NormalizedSessionResponse {
  return {
    sessionId: raw.session_id ?? '',
    welcomeText: raw.welcome_text,
    seedQuestions: raw.seed_questions,
    aiDisabled: raw.ai_disabled,
    disabledReason: raw.disabled_reason,
  };
}

// ── Questions ───────────────────────────────────────────────────

export function normalizeQuestions(raw: RawQuestionsResponse): DiscoveryQuestion[] {
  if (!raw.questions || !Array.isArray(raw.questions)) {
    return [];
  }

  // Sort by sort_order (if present) before mapping — preserves backend ordering
  const sorted = [...raw.questions].sort(
    (a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0),
  );

  return sorted.map((q) => ({
    id: String(q.question_id ?? q.id),
    question: q.question || q.question_text || '',
    answers: (q.answers || q.options || []).map((a) => ({
      id: String(a.id),
      text: a.text || a.answer_text || a.answer || '',
    })),
    allowOther: q.allow_other,
    productTypeId: q.product_type_id,
  }));
}

// ── Feedback ────────────────────────────────────────────────────

export interface NormalizedFeedbackResponse {
  success: boolean;
  feedbackId: string;
  message?: string;
}

export function normalizeFeedbackResponse(raw: RawFeedbackResponse): NormalizedFeedbackResponse {
  return {
    success: raw.success ?? false,
    feedbackId: raw.feedbackId ?? raw.feedback_id ?? '',
    message: raw.message,
  };
}
