import React from 'react';
import { useCountdown } from '../../hooks/useCountdown.js';

interface ReconnectInfo {
    attempt: number;
    maxAttempts: number;
    delayMs: number;
}

export interface SearchAnswerSkeletonProps {
    connectionLost?: boolean;
    connectionStatus?: string;
    reconnectInfo?: ReconnectInfo | null;
}

export const SearchAnswerSkeleton: React.FC<SearchAnswerSkeletonProps> = ({
    connectionLost = false,
    connectionStatus,
    reconnectInfo,
}) => {
    const countdown = useCountdown(reconnectInfo, connectionStatus === 'reconnecting');

    // Reconnecting after first attempt — show attempt info
    if (connectionLost && connectionStatus === 'reconnecting' && reconnectInfo && reconnectInfo.attempt >= 2) {
        return (
            <div className="omniguide-answer-skeleton omniguide-answer-skeleton--lost">
                <p className="omniguide-answer-skeleton__lost-text">
                    {countdown !== null && countdown > 0
                        ? `Next try in ${countdown}s (${reconnectInfo.attempt}/${reconnectInfo.maxAttempts})`
                        : <>Reconnecting<span className="omniguide-chat__connecting-dots"><span>.</span><span>.</span><span>.</span></span> ({reconnectInfo.attempt}/{reconnectInfo.maxAttempts})</>}
                </p>
            </div>
        );
    }

    // Disconnected (gave up)
    if (connectionLost) {
        return (
            <div className="omniguide-answer-skeleton omniguide-answer-skeleton--lost">
                <p className="omniguide-answer-skeleton__lost-text">
                    Connection lost while waiting for a response.
                </p>
            </div>
        );
    }

    // Default: loading skeleton lines
    return (
        <div className="omniguide-answer-skeleton">
            <div className="omniguide-answer-skeleton__line" style={{ width: '100%' }} />
            <div className="omniguide-answer-skeleton__line" style={{ width: '85%' }} />
            <div className="omniguide-answer-skeleton__line" style={{ width: '65%' }} />
            <div className="omniguide-answer-skeleton__line" style={{ width: '40%' }} />
        </div>
    );
};
