/**
 * BigCommerce Hydration Service
 *
 * Provides product and category hydration via the Omniguide BC endpoints.
 * Replaces duplicated fetchDataByIds/mergeEntityData logic that was
 * copy-pasted across search, product-recommendations, and category-recommendations.
 */

import type { BCProduct, BCCategory } from '../types.js';
import { API_ENDPOINTS } from '@swiftotter/omniguide-core';

// =========================================
// Configuration
// =========================================

export interface HydrationConfig {
  /** Omniguide backend base URL */
  apiBaseUrl: string;
  /** Website identifier (sent as website_code) */
  websiteId: string;
  /** Function to get the BigCommerce GraphQL storefront token */
  getGraphQLToken?: () => string | null;
}

// =========================================
// Hydration Key Definitions
// =========================================

/** Fields to fill from BC product data when the original value is empty */
export const PRODUCT_HYDRATE_KEYS = [
  'entityId',
  'name',
  'display_name',
  'product_line',
  'sku',
  'path',
  'url',
  'price',
  'imageUrl',
  'brandId',
  'brand',
  'defaultImage',
  'images',
] as const;

/** Fields to fill from BC category data when the original value is empty */
export const CATEGORY_HYDRATE_KEYS = [
  'entityId',
  'name',
  'path',
  'url',
  'imageUrl',
  'description',
] as const;

// =========================================
// Core Utilities
// =========================================

/**
 * Merge an original partial object with a fully-fetched object.
 * Only fills in fields that are null/undefined/empty in the original.
 */
export function mergeEntityData<T extends Record<string, unknown>>(
  original: T,
  fetched: Record<string, unknown> | null | undefined,
  hydrateKeys: readonly string[],
): T {
  if (!fetched) return original;
  if (!original) return fetched as T;

  const merged = { ...original };

  for (const key of hydrateKeys) {
    const originalValue = merged[key];
    const fetchedValue = fetched[key];

    const isOriginalEmpty =
      originalValue === null ||
      originalValue === undefined ||
      (typeof originalValue === 'string' && originalValue.trim() === '') ||
      (typeof originalValue === 'object' &&
        originalValue !== null &&
        Object.keys(originalValue).length === 0);

    if (isOriginalEmpty && fetchedValue !== undefined && fetchedValue !== null) {
      (merged as Record<string, unknown>)[key] = fetchedValue;
    }
  }

  return merged;
}

/**
 * Generic function to fetch entity data by IDs from an Omniguide BC endpoint.
 */
export async function fetchDataByIds<T>(
  config: HydrationConfig,
  entityIds: (string | number)[],
  endpoint: string,
  idKey: string,
  entityKey: string,
): Promise<T[]> {
  if (!entityIds || entityIds.length === 0) return [];

  const graphqlToken = config.getGraphQLToken?.() ?? null;

  try {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };

    if (graphqlToken) {
      headers['X-Storefront-Token'] = graphqlToken;
    }

    const url = `${config.apiBaseUrl}${endpoint}`;
    const response = await fetch(url, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        [idKey]: entityIds,
        website_code: config.websiteId,
        graphql_token: graphqlToken,
      }),
    });

    if (!response.ok) {
      return [];
    }

    const data = await response.json();
    return (data?.[entityKey] as T[]) || [];
  } catch {
    return [];
  }
}

// =========================================
// Product Hydration
// =========================================

/**
 * Hydrate products with BigCommerce data (prices, images, URLs, brands).
 * Fetches by SKU from the Omniguide BC products endpoint and merges.
 */
export async function hydrateProducts(
  config: HydrationConfig,
  products: Record<string, unknown>[],
): Promise<Record<string, unknown>[]> {
  if (!products || products.length === 0) return [];

  const skusToFetch = products
    .map((p) => p['sku'] as string)
    .filter(Boolean);

  if (skusToFetch.length === 0) return products;

  const fetchedProducts = await fetchDataByIds<BCProduct>(
    config,
    skusToFetch,
    API_ENDPOINTS.BC_SEARCH_PRODUCTS,
    'skus',
    'products',
  );

  const fetchedMap = new Map<string, BCProduct>();
  for (const product of fetchedProducts) {
    if (product.sku) {
      fetchedMap.set(product.sku, product);
    }
  }

  return products.map((original) => {
    const sku = original['sku'] as string | undefined;
    const fetched = sku ? fetchedMap.get(sku) : undefined;

    const merged = mergeEntityData(original, fetched ?? null, PRODUCT_HYDRATE_KEYS);

    // Map BC-specific fields to common product card fields
    if (fetched) {
      if (!merged['image_url'] && fetched.imageUrl) {
        (merged as Record<string, unknown>)['image_url'] = fetched.imageUrl;
      }
      if (!merged['image_url'] && (fetched as Record<string, unknown>)['defaultImage']) {
        const defaultImage = (fetched as Record<string, unknown>)['defaultImage'] as Record<string, unknown> | undefined;
        if (defaultImage?.['url']) {
          (merged as Record<string, unknown>)['image_url'] = defaultImage['url'];
        }
      }
      if (!merged['url'] && fetched.path) {
        (merged as Record<string, unknown>)['url'] = fetched.path;
      }
      if (!merged['product_line'] && (fetched as Record<string, unknown>)['brand']) {
        const brand = (fetched as Record<string, unknown>)['brand'];
        if (typeof brand === 'object' && brand !== null && 'name' in brand) {
          (merged as Record<string, unknown>)['product_line'] = (brand as Record<string, unknown>)['name'];
        } else if (typeof brand === 'string') {
          (merged as Record<string, unknown>)['product_line'] = brand;
        }
      }
      if (!merged['price'] && (fetched as Record<string, unknown>)['price']) {
        const price = (fetched as Record<string, unknown>)['price'];
        if (typeof price === 'object' && price !== null && 'value' in price) {
          (merged as Record<string, unknown>)['price'] = (price as Record<string, unknown>)['value'];
        }
      }
      if (!merged['retail_price'] && (fetched as Record<string, unknown>)['price']) {
        const price = (fetched as Record<string, unknown>)['price'] as Record<string, unknown>;
        const retailPrice = price?.['retailPrice'] as Record<string, unknown> | undefined;
        if (retailPrice?.['value']) {
          (merged as Record<string, unknown>)['retail_price'] = retailPrice['value'];
        }
      }
    }

    return merged;
  });
}

// =========================================
// Category Hydration
// =========================================

/**
 * Hydrate categories with BigCommerce data (images, URLs, descriptions).
 * Fetches by entity ID from the Omniguide BC categories endpoint and merges.
 */
export async function hydrateCategories(
  config: HydrationConfig,
  categories: Record<string, unknown>[],
): Promise<Record<string, unknown>[]> {
  if (!categories || categories.length === 0) return [];

  const categoryIds = categories
    .map((c) => parseInt(String(c['id'] || c['entityId']), 10))
    .filter(Boolean);

  if (categoryIds.length === 0) return [];

  const fetchedCategories = await fetchDataByIds<BCCategory>(
    config,
    categoryIds,
    API_ENDPOINTS.BC_SEARCH_CATEGORIES,
    'category_ids',
    'categories',
  );

  const fetchedMap = new Map<number, BCCategory>();
  for (const category of fetchedCategories) {
    if (category.entityId) {
      fetchedMap.set(category.entityId, category);
    }
  }

  return categories.map((original) => {
    const id = parseInt(String(original['id'] || original['entityId']), 10);
    const fetched = id ? fetchedMap.get(id) : undefined;

    return mergeEntityData(original, fetched ?? null, CATEGORY_HYDRATE_KEYS);
  });
}

// =========================================
// Convenience: Hydrate single products
// =========================================

/**
 * Hydrate a single alternative product with BC data.
 * Convenience wrapper around hydrateProducts for single-product cases.
 */
export async function hydrateAlternativeProduct(
  config: HydrationConfig,
  alternative: Record<string, unknown> | null,
): Promise<Record<string, unknown> | null> {
  if (!alternative) return null;

  try {
    const hydrated = await hydrateProducts(config, [alternative]);
    return hydrated[0] || alternative;
  } catch {
    return alternative;
  }
}

/**
 * Hydrate a single current product with BC data.
 * Convenience wrapper around hydrateProducts for single-product cases.
 */
export async function hydrateCurrentProduct(
  config: HydrationConfig,
  currentProduct: Record<string, unknown> | null,
): Promise<Record<string, unknown> | null> {
  if (!currentProduct) return null;

  try {
    const hydrated = await hydrateProducts(config, [currentProduct]);
    return hydrated[0] || currentProduct;
  } catch {
    return currentProduct;
  }
}
