/**
 * Hook for handling WebSocket message processing and token buffering
 *
 * Platform-agnostic — hydration is injected via the ChatHydration interface,
 * so BigCommerce, Magento, etc. each provide their own implementation.
 */

import { useCallback, useRef, useEffect, type MutableRefObject, type Dispatch, type SetStateAction } from 'react';
import { ERROR_MESSAGES, createResponseTimer, createScopedLogger, setRegistrySessionId } from '@swiftotter/omniguide-core';
import type { ResponseTimer } from '@swiftotter/omniguide-core';

const log = createScopedLogger('useChatMessageHandler');
import type {
    UseChatMessageHandlerOptions,
    UseChatMessageHandlerReturn,
    ChatMessage,
    ChatHydration,
} from '../types.js';

const generateId = () => `msg_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;

export const useChatMessageHandler = ({
    websiteId,
    setMessages,
    setIsLoading,
    setPipelineStatus,
    setIsThinking,
    setIsTimedOut,
    setError,
    setConversationId,
    setSessionId,
    setPendingIntentQuestion,
    setPendingClarificationQuestion,
    currentMessageIdRef,
    hydration,
    query,
    messages,
    buildFallbackSearchUrl,
}: UseChatMessageHandlerOptions): UseChatMessageHandlerReturn => {
    // Token batching for smoother rendering
    const tokenBufferRef = useRef('');
    const tokenFlushTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const streamingResponseRef = useRef('');

    // Refs for values that change frequently but shouldn't trigger handleMessage recreation.
    // Without refs, handleMessage would be recreated on every render (because messages/query/hydration
    // change), which would cause useChatConnection's connect callback to change, which would trigger
    // the useEffect cleanup (disconnect) and reconnect — creating an infinite reconnection loop.
    const hydrationRef = useRef(hydration);
    const queryRef = useRef(query);
    const messagesRef = useRef(messages);
    hydrationRef.current = hydration;
    queryRef.current = query;
    messagesRef.current = messages;

    // Ref for fallback URL builder so it doesn't trigger handleMessage recreation
    const buildFallbackSearchUrlRef = useRef(buildFallbackSearchUrl);
    buildFallbackSearchUrlRef.current = buildFallbackSearchUrl;

    // Response timer for latency handling (Non-Negotiable #4)
    const responseTimerRef = useRef<ResponseTimer | null>(null);

    // Initialize response timer
    useEffect(() => {
        responseTimerRef.current = createResponseTimer({
            onThinking: () => {
                log.debug('Entering "thinking" state after 3s');
                setIsThinking(true);
            },
            onTimeout: () => {
                log.debug('Response timed out after 10s');
                setIsTimedOut(true);
                setIsLoading(false);
                setError(ERROR_MESSAGES.TIMEOUT);
            },
            onCancel: () => {
                setIsThinking(false);
                setIsTimedOut(false);
            },
        });

        return () => {
            if (responseTimerRef.current) {
                responseTimerRef.current.destroy();
            }
        };
    }, [setIsThinking, setIsTimedOut, setIsLoading, setError]);

    // Cleanup token flush timeout on unmount
    useEffect(() => {
        return () => {
            if (tokenFlushTimeoutRef.current) {
                clearTimeout(tokenFlushTimeoutRef.current);
                tokenFlushTimeoutRef.current = null;
            }
        };
    }, []);

    /**
     * Flush buffered tokens to the message
     */
    const flushTokenBuffer = useCallback(() => {
        if (tokenBufferRef.current && currentMessageIdRef.current) {
            const bufferedContent = tokenBufferRef.current;
            tokenBufferRef.current = '';

            setMessages(prev => prev.map(m =>
                m.id === currentMessageIdRef.current
                    ? { ...m, content: m.content + bufferedContent, isStreaming: true }
                    : m
            ));
        }
    }, [setMessages, currentMessageIdRef]);

    /**
     * Add token to buffer and schedule flush
     */
    const bufferToken = useCallback((token: string) => {
        tokenBufferRef.current += token;
        streamingResponseRef.current += token;

        // Clear existing timeout and schedule new flush
        if (tokenFlushTimeoutRef.current) {
            clearTimeout(tokenFlushTimeoutRef.current);
        }

        tokenFlushTimeoutRef.current = setTimeout(flushTokenBuffer, 50); // 50ms batching
    }, [flushTokenBuffer]);

    /**
     * Start response timer
     */
    const startResponseTimer = useCallback(() => {
        if (responseTimerRef.current) {
            responseTimerRef.current.start();
        }
    }, []);

    /**
     * Reset streaming state for new message
     */
    const resetStreamingState = useCallback(() => {
        streamingResponseRef.current = '';
        tokenBufferRef.current = '';
    }, []);

    /**
     * Handle WebSocket messages
     */
    const handleMessage = useCallback((msg: { type: string; content?: unknown; status?: string; session_id?: string }) => {
        // Cancel response timer on any message (Non-Negotiable #4)
        if (responseTimerRef.current) {
            responseTimerRef.current.cancel();
        }

        switch (msg.type) {
            case 'status': {
                const status = msg.status || (msg.content as string);
                setPipelineStatus(status === 'done' ? 'idle' : status);

                if (status === 'done') {
                    // Flush any remaining tokens
                    flushTokenBuffer();
                    setIsLoading(false);

                    // Mark message as no longer streaming
                    if (currentMessageIdRef.current) {
                        setMessages(prev => prev.map(m =>
                            m.id === currentMessageIdRef.current
                                ? { ...m, isStreaming: false }
                                : m
                        ));
                    }
                }
                break;
            }

            case 'token':
                if (msg.content) {
                    bufferToken(msg.content as string);
                }
                break;

            case 'answer':
                // Final answer - replace accumulated tokens with authoritative response
                flushTokenBuffer();
                if (currentMessageIdRef.current && msg.content) {
                    setMessages(prev => prev.map(m =>
                        m.id === currentMessageIdRef.current
                            ? { ...m, content: msg.content as string, isStreaming: false }
                            : m
                    ));
                    streamingResponseRef.current = msg.content as string;
                }
                break;

            case 'sources':
                if (msg.content && Array.isArray(msg.content)) {
                    hydrationRef.current.hydrateSources(msg.content);
                }
                break;

            case 'suggestions':
                if (currentMessageIdRef.current && msg.content) {
                    setMessages(prev => prev.map(m =>
                        m.id === currentMessageIdRef.current
                            ? { ...m, suggestions: msg.content as string[] }
                            : m
                    ));
                }
                break;

            case 'metadata':
                // Store for analytics - not displayed to user
                if (currentMessageIdRef.current && msg.content) {
                    setMessages(prev => prev.map(m =>
                        m.id === currentMessageIdRef.current
                            ? { ...m, metadata: msg.content as Record<string, unknown> }
                            : m
                    ));
                }
                break;

            case 'intent_question':
                if (msg.content) {
                    setPendingIntentQuestion(msg.content);
                    setIsLoading(false);
                    setPipelineStatus('idle');
                    setMessages(prev => prev.map(m =>
                        m.id === currentMessageIdRef.current
                            ? { ...m, intentQuestion: msg.content, isStreaming: false }
                            : m
                    ));
                }
                break;

            case 'discovery_question': {
                if (msg.content) {
                    const raw = msg.content as Record<string, unknown>;
                    const answers = (raw['answers'] as Array<Record<string, unknown>>) || [];

                    // Normalize discovery question format
                    const discoveryQuestion = {
                        question_id: raw['question_id'],
                        question_text: raw['question_text'],
                        question_summary: raw['question_summary'],
                        sort_order: raw['sort_order'],
                        is_root: raw['is_root'],
                        parent_answer_id: raw['parent_answer_id'],
                        // Legacy field mappings
                        id: raw['question_id'],
                        question: raw['question_text'],
                        summary: raw['question_summary'],
                        answers: answers.map(answer => ({
                            id: answer['id'],
                            answer_text: answer['answer_text'],
                            explanation: answer['explanation'],
                            examples: answer['examples'],
                            is_other_option: answer['is_other_option'],
                            has_child_question: answer['has_child_question'],
                            answer: answer['answer_text'],
                        })),
                        _isDiscoveryQuestion: true,
                    };

                    setPendingIntentQuestion(discoveryQuestion);
                    setIsLoading(false);
                    setPipelineStatus('idle');
                    setMessages(prev => prev.map(m =>
                        m.id === currentMessageIdRef.current
                            ? { ...m, intentQuestion: discoveryQuestion, isStreaming: false }
                            : m
                    ));
                }
                break;
            }

            case 'clarification_question':
                if (msg.content) {
                    setPendingClarificationQuestion(msg.content);
                    setIsLoading(false);
                    setPipelineStatus('idle');
                    setMessages(prev => prev.map(m =>
                        m.id === currentMessageIdRef.current
                            ? { ...m, clarificationQuestion: msg.content, isStreaming: false }
                            : m
                    ));
                }
                break;

            case 'session_id': {
                if (msg.content || msg.session_id) {
                    const contentObj = msg.content as Record<string, unknown> | string | undefined;
                    const serverSessionId = (
                        (typeof contentObj === 'object' && contentObj !== null ? contentObj['session_id'] : undefined)
                        || msg.session_id
                        || contentObj
                    ) as string;
                    log.debug('Syncing session ID from server:', serverSessionId);
                    setSessionId(serverSessionId);
                    setRegistrySessionId(websiteId, serverSessionId);
                }
                break;
            }

            case 'user': {
                if (msg.content) {
                    const content = msg.content as Record<string, unknown>;
                    if (content['conversation_id']) {
                        setConversationId(content['conversation_id'] as string);
                    }
                    if (content['session_id']) {
                        const serverSessionId = content['session_id'] as string;
                        log.debug('Syncing session ID from user message:', serverSessionId);
                        setSessionId(serverSessionId);
                        setRegistrySessionId(websiteId, serverSessionId);
                    }
                    if (content['message_id'] && currentMessageIdRef.current) {
                        setMessages(prev => prev.map(m =>
                            m.id === currentMessageIdRef.current
                                ? { ...m, serverMessageId: content['message_id'] as string }
                                : m
                        ));
                    }
                }
                break;
            }

            case 'error': {
                const rawError = (msg.content as string) || 'An error occurred';
                log.error('Search WebSocket error:', rawError);
                setError('We encountered an error while processing your request. Please try again.');
                setIsLoading(false);
                setPipelineStatus('idle');

                const lastUserMessage = messagesRef.current.filter(m => m.role === 'user').pop();
                const userQuery = lastUserMessage?.content || queryRef.current || '';

                setMessages(prev => {
                    const filtered = prev.filter(m => (m as ChatMessage & { type?: string }).type !== 'thinking');
                    const errorMessage: ChatMessage = {
                        id: generateId(),
                        role: 'assistant',
                        content: ERROR_MESSAGES.GENERIC,
                        isError: true,
                        timestamp: new Date(),
                        fallbackSearch: userQuery
                            ? {
                                query: userQuery,
                                url: buildFallbackSearchUrlRef.current
                                    ? buildFallbackSearchUrlRef.current(userQuery)
                                    : `?q=${encodeURIComponent(userQuery)}`,
                            }
                            : undefined,
                    };
                    return [errorMessage, ...filtered];
                });
                break;
            }

            case 'products':
                if (currentMessageIdRef.current && msg.content && Array.isArray(msg.content)) {
                    log.debug('Hydrating products:', msg.content.length);
                    hydrationRef.current.hydrateProducts(msg.content);
                } else {
                    log.debug('Products received but skipped:', {
                        hasMessageId: !!currentMessageIdRef.current,
                        hasContent: !!msg.content,
                        isArray: Array.isArray(msg.content),
                    });
                }
                break;

            case 'categories':
                if (currentMessageIdRef.current && msg.content && Array.isArray(msg.content)) {
                    log.debug('Categories received:', msg.content.length);
                    hydrationRef.current.hydrateCategories(msg.content);
                }
                break;

            case 'documentation':
                if (currentMessageIdRef.current && msg.content && Array.isArray(msg.content)) {
                    hydrationRef.current.hydrateDocumentation(msg.content);
                }
                break;

            case 'recommendations':
                if (currentMessageIdRef.current && msg.content) {
                    const recContent = msg.content as Record<string, unknown>;
                    const keyFilterQuestions = recContent['key_filter_questions'];
                    setMessages(prev => prev.map(m =>
                        m.id === currentMessageIdRef.current
                            ? {
                                ...m,
                                recommendations: recContent,
                                ...(keyFilterQuestions ? { keyFilterQuestions } : {}),
                            }
                            : m
                    ));
                }
                break;

            default:
                log.debug('Unhandled WebSocket message type:', msg.type);
        }
    }, [
        setMessages,
        setIsLoading,
        setPipelineStatus,
        setPendingIntentQuestion,
        setPendingClarificationQuestion,
        setConversationId,
        setSessionId,
        setError,
        currentMessageIdRef,
        flushTokenBuffer,
        bufferToken,
        // hydration, query, messages, buildFallbackSearchUrl accessed via refs to keep handleMessage stable.
        // This prevents infinite reconnection loops in useChatConnection.
    ]);

    return {
        handleMessage,
        startResponseTimer,
        resetStreamingState,
        flushTokenBuffer,
        streamingResponseRef,
    };
};
