import { useState, useEffect, useRef, useMemo } from 'react';
import { extractSkusFromMarkdown } from '@swiftotter/omniguide-core';

export interface ChatMessageLike {
    role: string;
    content?: string;
}

export interface UseProductUrlFetchingOptions {
    messages: ChatMessageLike[];
    fetchProductUrls?: (skus: string[]) => Promise<Record<string, string>>;
}

export interface UseProductUrlFetchingReturn {
    productUrls: Record<string, string>;
}

/**
 * Extracts SKUs from chat messages and fetches real product URLs.
 * Debounces fetches (150ms) and deduplicates to avoid redundant API calls.
 */
export function useProductUrlFetching({
    messages,
    fetchProductUrls,
}: UseProductUrlFetchingOptions): UseProductUrlFetchingReturn {
    const [productUrls, setProductUrls] = useState<Record<string, string>>({});
    const fetchedSkusRef = useRef(new Set<string>());
    const pendingFetchRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Extract all SKUs from all assistant messages
    const allSkus = useMemo(() => {
        const skus = new Set<string>();
        messages.forEach((msg) => {
            if (msg.role === 'assistant' && msg.content) {
                const extractedSkus = extractSkusFromMarkdown(msg.content);
                extractedSkus.forEach((sku) => skus.add(sku));
            }
        });
        return Array.from(skus);
    }, [messages]);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            fetchedSkusRef.current.clear();
            if (pendingFetchRef.current) {
                clearTimeout(pendingFetchRef.current);
            }
        };
    }, []);

    // Fetch real product URLs only for SKUs we haven't fetched yet (debounced)
    useEffect(() => {
        if (!fetchProductUrls) return;

        const newSkus = allSkus.filter((sku) => !fetchedSkusRef.current.has(sku));
        if (newSkus.length === 0) return;

        if (pendingFetchRef.current) {
            clearTimeout(pendingFetchRef.current);
        }

        // Debounce: wait 150ms for more SKUs to arrive before fetching
        pendingFetchRef.current = setTimeout(() => {
            const skusToFetch = allSkus.filter((sku) => !fetchedSkusRef.current.has(sku));
            if (skusToFetch.length > 0) {
                skusToFetch.forEach((sku) => fetchedSkusRef.current.add(sku));
                fetchProductUrls(skusToFetch).then((urls) => {
                    setProductUrls((prev) => ({ ...prev, ...urls }));
                });
            }
        }, 150);

        return () => {
            if (pendingFetchRef.current) {
                clearTimeout(pendingFetchRef.current);
            }
        };
    }, [allSkus, fetchProductUrls]);

    return { productUrls };
}
