/**
 * Feedback API for submitting user feedback.
 * Uses normalize → validate → return pattern for responses.
 */

import { ApiClient } from './api.js';
import { APIError } from './errors.js';
import { normalizeFeedbackResponse } from './adapters/rest/normalize.js';
import { RestFeedbackResponseSchema } from './adapters/rest/schemas.js';

export interface FeedbackData {
  /** Entity identifier (SKU, message ID, etc.) */
  entityId: string;
  /** Entity type */
  entityType: 'message' | 'product_recommendation' | 'category_recommendation';
  /** Vote direction (1 for thumbs up, -1 for thumbs down) */
  vote: 1 | -1;
  /** Optional feedback comment */
  comment?: string;
  /** Optional context metadata */
  context?: Record<string, unknown>;
}

export interface FeedbackResponse {
  success: boolean;
  feedbackId?: string;
  message?: string;
}

/**
 * Feedback API client
 */
export class FeedbackAPI {
  private api: ApiClient;
  private websiteCode: string;
  private getSessionId: () => string | null;

  constructor(config: {
    apiBaseUrl: string;
    websiteCode: string;
    getSessionId: () => string | null;
  }) {
    this.api = new ApiClient({ baseUrl: config.apiBaseUrl, timeout: 10000 });
    this.websiteCode = config.websiteCode;
    this.getSessionId = config.getSessionId;
  }

  /**
   * Submit feedback to the API
   */
  async submitFeedback(feedbackData: FeedbackData): Promise<FeedbackResponse> {
    const sessionId = this.getSessionId();

    if (!sessionId) {
      throw new APIError('Session expired. Please refresh the page.', {
        context: { reason: 'no_session' },
      });
    }

    const payload = {
      session_id: sessionId,
      website_code: this.websiteCode,
      entity_type: feedbackData.entityType,
      entity_id: feedbackData.entityId,
      vote: feedbackData.vote,
      comment: feedbackData.comment ?? '',
      context: feedbackData.context ?? {},
    };

    try {
      const response = await this.api.post<Record<string, unknown>>('/api/v1/feedback', payload);
      const normalized = normalizeFeedbackResponse(response.data);
      const validated = RestFeedbackResponseSchema.safeParse(normalized);
      return validated.success ? validated.data : { success: false, feedbackId: '' };
    } catch (error) {
      if (error instanceof APIError) {
        // Provide user-friendly error messages based on status
        if (error.status === 400) {
          throw new APIError('Invalid feedback data. Please try again.', {
            cause: error,
            status: error.status,
          });
        } else if (error.status === 404) {
          throw new APIError('Service not found. Please contact support.', {
            cause: error,
            status: error.status,
          });
        } else if (error.status === 429) {
          throw new APIError('Too many requests. Please wait a moment.', {
            cause: error,
            status: error.status,
          });
        } else if (error.status && error.status >= 500) {
          throw new APIError('Service error. Please try again later.', {
            cause: error,
            status: error.status,
          });
        }
      }
      throw error;
    }
  }

  /**
   * Submit thumbs up feedback
   */
  async thumbsUp(
    entityId: string,
    entityType: FeedbackData['entityType'],
    options?: { comment?: string; context?: Record<string, unknown> }
  ): Promise<FeedbackResponse> {
    return this.submitFeedback({
      entityId,
      entityType,
      vote: 1,
      ...options,
    });
  }

  /**
   * Submit thumbs down feedback
   */
  async thumbsDown(
    entityId: string,
    entityType: FeedbackData['entityType'],
    options?: { comment?: string; context?: Record<string, unknown> }
  ): Promise<FeedbackResponse> {
    return this.submitFeedback({
      entityId,
      entityType,
      vote: -1,
      ...options,
    });
  }
}

/**
 * Create a feedback API instance
 */
export function createFeedbackAPI(config: {
  apiBaseUrl: string;
  websiteCode: string;
  getSessionId: () => string | null;
}): FeedbackAPI {
  return new FeedbackAPI(config);
}
