import React, { useState, useRef, useEffect, useMemo } from 'react';
import { parseMarkdown } from '../../utils/index.js';
import { SearchSuggestionChips } from './SearchSuggestionChips.js';
import { SearchIntentQuestionUI } from './SearchIntentQuestionUI.js';
import type { IntentQuestion } from './SearchIntentQuestionUI.js';
import { SearchClarificationQuestionUI } from './SearchClarificationQuestionUI.js';
import type { ClarificationQuestion } from './SearchClarificationQuestionUI.js';
import { SearchPipelineStatusIndicator } from './SearchPipelineStatusIndicator.js';
import { SearchThinkingIndicator } from './SearchThinkingIndicator.js';
import { SearchAnswerSkeleton } from './SearchAnswerSkeleton.js';

interface SourceData {
    type: string;
    data?: {
        sku?: string;
        url?: string;
        path?: string;
        display_name?: string;
        name?: string;
        product_line?: string;
        brand?: { name?: string } | string;
    };
}

interface UserMessage {
    id: string;
    content: string;
}

interface AssistantMessage {
    id?: string;
    content?: string;
    isStreaming?: boolean;
    sources?: SourceData[];
    suggestions?: string[];
    intentQuestion?: IntentQuestion;
    clarificationQuestion?: ClarificationQuestion;
    queryContext?: string;
}

export interface SearchQAMessageProps {
    userMessage: UserMessage;
    assistantMessage?: AssistantMessage | null;
    onSuggestionClick: (suggestion: string) => void;
    onIntentAnswer: (answerText: string, answerId: string | number, options?: Record<string, unknown>) => void;
    onCustomIntentAnswer: (customText: string) => void;
    onClarificationAnswer: (answerText: string, optionId: string | number, paramName: string) => void;
    onCustomClarificationAnswer: (customText: string) => void;
    selectedSuggestions?: string[];
    pipelineStatus?: string | null;
    isLoading?: boolean;
    variant?: 'search' | 'category';
    productUrls?: Record<string, string>;
    isMobile?: boolean;
    conversationId?: string;
    connectionStatus?: string;
    reconnectInfo?: { attempt: number; maxAttempts: number; delayMs: number } | null;
    onFeedbackSubmit?: (data: Record<string, unknown>) => Promise<unknown>;
    FeedbackWidgetComponent?: React.ComponentType<{
        entityId: string;
        entityType: string;
        context: Record<string, unknown>;
    }>;
}

export const SearchQAMessage: React.FC<SearchQAMessageProps> = ({
    userMessage,
    assistantMessage,
    onSuggestionClick,
    onIntentAnswer,
    onCustomIntentAnswer,
    onClarificationAnswer,
    onCustomClarificationAnswer,
    selectedSuggestions = [],
    pipelineStatus,
    isLoading,
    variant = 'search',
    productUrls = {},
    connectionStatus,
    reconnectInfo,
    conversationId,
    FeedbackWidgetComponent,
}) => {
    const [isQuestionExpanded, setIsQuestionExpanded] = useState(false);
    const questionRef = useRef<HTMLHeadingElement>(null);
    const [isTruncated, setIsTruncated] = useState(false);

    useEffect(() => {
        if (questionRef.current) {
            const element = questionRef.current;
            setIsTruncated(element.scrollHeight > element.clientHeight);
        }
    }, [userMessage.content]);

    const { sourceProductUrls, sourceProductNames } = useMemo(() => {
        const urlMap: Record<string, string> = { ...productUrls };
        const nameMap: Record<string, string> = {};
        const sources = assistantMessage?.sources || [];
        sources.forEach(source => {
            if (source.type === 'product' && source.data) {
                const { sku, url, path, display_name, name, product_line, brand } = source.data;
                if (sku) {
                    if (url || path) {
                        urlMap[String(sku)] = (url || path)!;
                    }
                    const shortName = name || display_name;
                    if (shortName) {
                        // Only prepend brand for display_name (short name); full name already includes it
                        if (!name && display_name) {
                            const brandName = product_line ||
                                (typeof brand === 'object' ? brand?.name : typeof brand === 'string' ? brand : null);
                            nameMap[String(sku)] = brandName ? `${brandName} ${shortName}` : shortName;
                        } else {
                            nameMap[String(sku)] = shortName;
                        }
                    }
                }
            }
        });
        return { sourceProductUrls: urlMap, sourceProductNames: nameMap };
    }, [assistantMessage?.sources, productUrls]);

    const isStreaming = assistantMessage?.isStreaming;

    const hasProductUrls = Object.keys(sourceProductUrls).length > 0;
    const sanitizedContent = parseMarkdown(assistantMessage?.content || '', {
        linkColor: 'var(--omniguide-color-primary)',
        productUrls: sourceProductUrls,
        productNames: sourceProductNames,
        requireCorrectUrls: !hasProductUrls,
    }) || '';
    const hasContent = (assistantMessage?.content?.length ?? 0) > 0;
    const hasSubstantialContent = (assistantMessage?.content?.length ?? 0) > 100;
    const isConnectionDisabled = connectionStatus === 'connecting' || connectionStatus === 'reconnecting' || connectionStatus === 'disconnected';
    const showInlineStatus = isLoading && pipelineStatus
        && pipelineStatus !== 'idle' && pipelineStatus !== 'generating'
        && !(hasSubstantialContent && pipelineStatus === 'finalizing' && !isStreaming);

    const questionClassName = `omniguide-qa__question ${variant === 'category' ? 'omniguide-qa__question--category' : ''} ${isTruncated ? 'omniguide-qa__question--truncated' : ''}`.trim();

    const handleQuestionClick = () => {
        if (isTruncated) {
            setIsQuestionExpanded(!isQuestionExpanded);
        }
    };

    return (
        <div className="omniguide-qa">
            <h3
                ref={questionRef}
                className={questionClassName}
                onClick={handleQuestionClick}
            >
                {userMessage.content}
            </h3>
            {assistantMessage && (
                <>
                    <div className="omniguide-qa__answer">
                        {hasContent ? (
                            <span dangerouslySetInnerHTML={{ __html: sanitizedContent }} />
                        ) : !hasContent && isConnectionDisabled ? (
                            <SearchAnswerSkeleton connectionLost connectionStatus={connectionStatus} reconnectInfo={reconnectInfo} />
                        ) : (isStreaming || isLoading) ? (
                            <SearchAnswerSkeleton />
                        ) : null}
                        {isStreaming && hasContent && (
                            <span className="omniguide-streaming-cursor"></span>
                        )}
                        {showInlineStatus && (
                            <SearchPipelineStatusIndicator status={pipelineStatus!} />
                        )}
                    </div>
                    {!isStreaming && assistantMessage.intentQuestion && (
                        <SearchIntentQuestionUI
                            intentQuestion={assistantMessage.intentQuestion}
                            onAnswerClick={onIntentAnswer}
                            onCustomAnswer={onCustomIntentAnswer}
                        />
                    )}
                    {!isStreaming && assistantMessage.clarificationQuestion && (
                        <SearchClarificationQuestionUI
                            clarificationQuestion={assistantMessage.clarificationQuestion}
                            onAnswerClick={onClarificationAnswer}
                            onCustomAnswer={onCustomClarificationAnswer}
                        />
                    )}
                    {!isStreaming && !assistantMessage.intentQuestion && !assistantMessage.clarificationQuestion && (
                        <SearchSuggestionChips
                            suggestions={assistantMessage.suggestions}
                            onSuggestionClick={onSuggestionClick}
                            selectedSuggestions={selectedSuggestions}
                            variant={variant}
                        />
                    )}
                    {!isStreaming && assistantMessage.id && FeedbackWidgetComponent && (
                        <div className="omniguide-message__feedback">
                            <FeedbackWidgetComponent
                                entityId={assistantMessage.id}
                                entityType="message"
                                context={{
                                    query: userMessage.content,
                                    conversation_id: conversationId,
                                    message_role: 'assistant',
                                    has_sources: assistantMessage.sources && assistantMessage.sources.length > 0,
                                }}
                            />
                        </div>
                    )}
                </>
            )}
        </div>
    );
};
