/**
 * useFeedbackWidget — Shared hook that creates a FeedbackWidgetComponent
 * from the feedbackApi in OmniguideContext.
 *
 * Each rendered DiscoveryFeedbackWidget instance has its own React state
 * (vote, comment, phase, etc.), so multiple widgets on the same page
 * (e.g. category chat + search modal) operate independently.
 */

import React, { useCallback } from 'react';
import { DiscoveryFeedbackWidget, useOmniguideContext } from '@swiftotter/omniguide-react';
import type { FeedbackData as WidgetFeedbackData } from '@swiftotter/omniguide-react';
import { createScopedLogger } from '@swiftotter/omniguide-core';

const log = createScopedLogger('useFeedbackWidget');

export interface FeedbackWidgetComponentProps {
  entityId: string;
  entityType: string;
  context: Record<string, unknown>;
}

// ── Runtime guards for widget ↔ core type boundary ──────────────────

const VALID_ENTITY_TYPES = ['message', 'product_recommendation', 'category_recommendation'] as const;
type EntityType = (typeof VALID_ENTITY_TYPES)[number];

function isEntityType(value: string): value is EntityType {
  return (VALID_ENTITY_TYPES as readonly string[]).includes(value);
}

function isVote(value: number): value is 1 | -1 {
  return value === 1 || value === -1;
}

/**
 * Returns a memoized React component that renders DiscoveryFeedbackWidget
 * wired to the feedbackApi from context.
 *
 * Stable across re-renders unless feedbackApi itself changes.
 */
export function useFeedbackWidget(): React.ComponentType<FeedbackWidgetComponentProps> {
  const { feedbackApi } = useOmniguideContext();

  return useCallback(
    function FeedbackWidget(props: FeedbackWidgetComponentProps) {
      const handleFeedbackSubmit = async (data: WidgetFeedbackData) => {
        if (!feedbackApi) throw new Error('Feedback API not available');

        if (!isEntityType(data.entity_type)) {
          throw new Error(`Invalid entity_type: "${data.entity_type}"`);
        }
        if (!isVote(data.vote)) {
          throw new Error(`Invalid vote value: ${data.vote}`);
        }

        return feedbackApi.submitFeedback({
          entityId: data.entity_id,
          entityType: data.entity_type,
          vote: data.vote,
          comment: data.comment ?? '',
          context: data.context ?? {},
        });
      };

      if (!isEntityType(props.entityType)) {
        log.error(`Invalid entityType prop: "${props.entityType}"`);
        return null;
      }

      return (
        <DiscoveryFeedbackWidget
          {...props}
          entityType={props.entityType}
          onSubmit={handleFeedbackSubmit}
        />
      );
    },
    [feedbackApi],
  );
}
