/**
 * Session Registry — Namespaced session state for multi-instance safety.
 *
 * Replaces global window._aiChatSessionId, window._aiChatConversationId,
 * and window._aiChatSessionStart with a registry keyed by websiteId.
 * This allows multiple Omniguide instances (different websites) on the same page
 * without session collisions.
 *
 * conversationId is persisted to localStorage so it survives page reloads
 * (SOI-258 fix: without this, reloading mid-conversation caused websocket/session
 * errors and a stuck loading state).
 */

export interface OmniguideFeatureStatus {
  aiDisabled: boolean;
  // Future: searchDisabled, productFitDisabled, categoryGuideDisabled, etc.
}

export interface OmniguideSessionState {
  sessionId: string | null;
  conversationId: string | null;
  sessionStart: number | null;
  featureStatus: OmniguideFeatureStatus | null;
}

const REGISTRY_KEY = '__omniguideSessions';

function conversationStorageKey(websiteId: string): string {
  return `omniguide_conversation_id_${websiteId}`;
}

function readLocalStorage(key: string): string | null {
  try {
    return typeof window !== 'undefined' ? localStorage.getItem(key) : null;
  } catch {
    return null;
  }
}

function writeLocalStorage(key: string, value: string | null): void {
  try {
    if (typeof window === 'undefined') return;
    if (value) {
      localStorage.setItem(key, value);
    } else {
      localStorage.removeItem(key);
    }
  } catch {
    // localStorage may be unavailable (private browsing, full quota, etc.)
  }
}

function getRegistry(): Record<string, OmniguideSessionState> {
  if (typeof window === 'undefined') return {};
  const win = window as unknown as Record<string, unknown>;
  if (!win[REGISTRY_KEY]) {
    win[REGISTRY_KEY] = {};
  }
  return win[REGISTRY_KEY] as Record<string, OmniguideSessionState>;
}

function ensureEntry(websiteId: string): OmniguideSessionState {
  const registry = getRegistry();
  if (!registry[websiteId]) {
    // Restore conversationId from localStorage if available (page reload case)
    const storedConversationId = readLocalStorage(conversationStorageKey(websiteId));
    registry[websiteId] = {
      sessionId: null,
      conversationId: storedConversationId,
      sessionStart: null,
      featureStatus: null,
    };
  }
  return registry[websiteId];
}

export function getSessionId(websiteId: string): string | null {
  return ensureEntry(websiteId).sessionId;
}

export function setSessionId(websiteId: string, sessionId: string): void {
  ensureEntry(websiteId).sessionId = sessionId;
}

export function clearSessionId(websiteId: string): void {
  ensureEntry(websiteId).sessionId = null;
}

export function getConversationId(websiteId: string): string | null {
  return ensureEntry(websiteId).conversationId;
}

export function setConversationId(websiteId: string, conversationId: string | null): void {
  ensureEntry(websiteId).conversationId = conversationId;
  writeLocalStorage(conversationStorageKey(websiteId), conversationId);
}

export function getSessionStart(websiteId: string): number | null {
  return ensureEntry(websiteId).sessionStart;
}

export function setSessionStart(websiteId: string, start: number): void {
  ensureEntry(websiteId).sessionStart = start;
}

export function clearSession(websiteId: string): void {
  const registry = getRegistry();
  delete registry[websiteId];
  featureStatusSubscribers.delete(websiteId);
  writeLocalStorage(conversationStorageKey(websiteId), null);
}

// ── Feature Status ──────────────────────────────────────────────────

const featureStatusSubscribers = new Map<string, Set<(status: OmniguideFeatureStatus) => void>>();

export function getFeatureStatus(websiteId: string): OmniguideFeatureStatus | null {
  return ensureEntry(websiteId).featureStatus;
}

export function setFeatureStatus(websiteId: string, status: OmniguideFeatureStatus): void {
  ensureEntry(websiteId).featureStatus = status;
  const subs = featureStatusSubscribers.get(websiteId);
  if (subs) {
    subs.forEach((cb) => cb(status));
  }
}

export function onFeatureStatusChange(
  websiteId: string,
  callback: (status: OmniguideFeatureStatus) => void,
): () => void {
  if (!featureStatusSubscribers.has(websiteId)) {
    featureStatusSubscribers.set(websiteId, new Set());
  }
  const subs = featureStatusSubscribers.get(websiteId)!;
  subs.add(callback);
  return () => {
    subs.delete(callback);
    if (subs.size === 0) {
      featureStatusSubscribers.delete(websiteId);
    }
  };
}
