/**
 * Custom error types for Omniguide SDK
 *
 * Error handling is critical - the SDK must NEVER crash the host e-commerce site.
 * All errors should be catchable and recoverable.
 */

export class OmniguideError extends Error {
  readonly code: string;
  readonly context?: Record<string, unknown>;
  readonly cause?: Error;

  constructor(
    code: string,
    message: string,
    options?: { cause?: Error; context?: Record<string, unknown> }
  ) {
    super(message);
    this.name = 'OmniguideError';
    this.code = code;
    this.cause = options?.cause;
    this.context = options?.context;

    // Maintains proper stack trace for where error was thrown
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, OmniguideError);
    }
  }
}

/**
 * WebSocket connection errors
 */
export class WebSocketError extends OmniguideError {
  readonly readyState?: number;
  readonly url?: string;
  readonly closeCode?: number;
  readonly closeReason?: string;

  constructor(
    message: string,
    options?: {
      cause?: Error;
      context?: Record<string, unknown>;
      readyState?: number;
      url?: string;
      closeCode?: number;
      closeReason?: string;
    }
  ) {
    super('WEBSOCKET_ERROR', message, options);
    this.name = 'WebSocketError';
    this.readyState = options?.readyState;
    this.url = options?.url;
    this.closeCode = options?.closeCode;
    this.closeReason = options?.closeReason;
  }
}

/**
 * Connection timeout errors
 */
export class ConnectionTimeoutError extends WebSocketError {
  constructor(url: string, timeoutMs: number) {
    super(`Connection to ${url} timed out after ${timeoutMs}ms`, {
      context: { url, timeoutMs },
      url,
    });
    this.name = 'ConnectionTimeoutError';
  }
}

/**
 * Maximum reconnection attempts exceeded
 */
export class MaxReconnectsError extends WebSocketError {
  constructor(attempts: number) {
    super(`Maximum reconnection attempts (${attempts}) exceeded`, {
      context: { attempts },
    });
    this.name = 'MaxReconnectsError';
  }
}

/**
 * API request errors
 */
export class APIError extends OmniguideError {
  readonly status?: number;
  readonly statusText?: string;
  readonly url?: string;

  constructor(
    message: string,
    options?: {
      cause?: Error;
      context?: Record<string, unknown>;
      status?: number;
      statusText?: string;
      url?: string;
    }
  ) {
    super('API_ERROR', message, options);
    this.name = 'APIError';
    this.status = options?.status;
    this.statusText = options?.statusText;
    this.url = options?.url;
  }
}

/**
 * API timeout errors
 */
export class APITimeoutError extends APIError {
  constructor(url: string, timeoutMs: number) {
    super(`API request to ${url} timed out after ${timeoutMs}ms`, {
      context: { url, timeoutMs },
      url,
    });
    this.name = 'APITimeoutError';
  }
}

/**
 * Platform adapter not initialized
 */
export class PlatformNotInitializedError extends OmniguideError {
  constructor(platformName?: string) {
    super(
      'PLATFORM_NOT_INITIALIZED',
      `Platform adapter${platformName ? ` (${platformName})` : ''} is not initialized`,
      { context: { platformName } }
    );
    this.name = 'PlatformNotInitializedError';
  }
}

/**
 * Configuration validation errors
 */
export class ConfigurationError extends OmniguideError {
  constructor(message: string, context?: Record<string, unknown>) {
    super('CONFIGURATION_ERROR', message, { context });
    this.name = 'ConfigurationError';
  }
}

/**
 * Storage errors (localStorage unavailable, etc.)
 */
export class StorageError extends OmniguideError {
  constructor(message: string, cause?: Error) {
    super('STORAGE_ERROR', message, { cause });
    this.name = 'StorageError';
  }
}

/**
 * REST response parse errors — thrown when normalize → validate fails on a critical path.
 * Non-critical paths (questions, feedback) degrade gracefully via fallback defaults.
 */
export class SdkParseError extends OmniguideError {
  readonly endpoint: string;
  readonly zodError: unknown;

  constructor(endpoint: string, zodError: unknown) {
    super('SDK_PARSE_ERROR', `[Omniguide] Failed to parse ${endpoint} response`, {
      context: { endpoint },
    });
    this.name = 'SdkParseError';
    this.endpoint = endpoint;
    this.zodError = zodError;
  }
}

/**
 * Check if an error is a OmniguideError
 */
export function isOmniguideError(error: unknown): error is OmniguideError {
  return error instanceof OmniguideError;
}

/**
 * Safely wrap an error for logging/reporting
 */
export function wrapError(error: unknown, defaultMessage = 'An unknown error occurred'): OmniguideError {
  if (error instanceof OmniguideError) {
    return error;
  }

  if (error instanceof Error) {
    return new OmniguideError('UNKNOWN_ERROR', error.message, { cause: error });
  }

  return new OmniguideError('UNKNOWN_ERROR', defaultMessage, {
    context: { originalError: String(error) },
  });
}
