/**
 * BigCommerce-specific chat hydration hook.
 *
 * Implements the ChatHydration interface by enriching products, categories,
 * and content returned from the Omniguide WebSocket with data from the
 * BigCommerce Storefront / hydration API.
 */

import { useCallback, type Dispatch, type SetStateAction, type MutableRefObject } from 'react';
import { filterEmptyContent, createScopedLogger, type SourceItem } from '@swiftotter/omniguide-core';
import type { ChatMessage, ChatHydration } from '@swiftotter/omniguide-react';

const log = createScopedLogger('useBCChatHydration');

// ── Types ──────────────────────────────────────────────────────────

type Entity = Record<string, unknown>;

export interface BCChatHydrationAPI {
  /** Fetch full product data from BigCommerce (by SKU) */
  fetchProductData: (products: Entity[], storefrontToken: string) => Promise<Entity[]>;
  /** Fetch full category data from BigCommerce (by ID) */
  fetchCategoryData: (categories: Entity[], storefrontToken: string) => Promise<Entity[]>;
  /** Map content/documentation (no external fetch needed) */
  fetchContentData: (content: Entity[]) => Promise<Entity[]>;
}

export interface UseBCChatHydrationOptions {
  /** BigCommerce storefront token */
  storefrontToken: string;
  /** State setter for chat messages */
  setMessages: Dispatch<SetStateAction<ChatMessage[]>>;
  /** Ref to current message ID being streamed */
  currentMessageIdRef: MutableRefObject<string | null>;
  /** Analytics callback when recommendations are provided */
  trackRecommendationProvided?: (data: {
    messageId: string;
    recommendationType: string;
    itemCount: number;
    context: string;
  }) => void;
  /** BigCommerce API functions */
  api: BCChatHydrationAPI;
}

// ── Helpers ────────────────────────────────────────────────────────

function getPageContext(): string {
  if (typeof window === 'undefined') return 'search';
  if (window.location.pathname.includes('/products/')) return 'product';
  if (window.location.pathname.includes('/category/')) return 'category';
  return 'search';
}

/** Parse an entity ID from various possible fields. */
function parseEntityId(source: Entity): number {
  return parseInt(
    String(source['id'] ?? source['product_id'] ?? source['entityId'] ?? ''),
    10,
  );
}

/** Find a matching entity in a list by comparing numeric IDs. */
function matchById(source: Entity, candidates: Entity[]): Entity | undefined {
  const id = parseEntityId(source);
  if (isNaN(id)) return undefined;
  return candidates.find(
    (c) =>
      c['entityId'] === id ||
      c['id'] === id ||
      parseInt(String(c['id']), 10) === id,
  );
}

/** Merge a Omniguide product with a BigCommerce product. */
function mergeProduct(omniguideProduct: Entity, bcProduct: Entity | undefined): Entity {
  const merged: Entity = {
    ...omniguideProduct,
    ...bcProduct,
    // Preserve Omniguide-specific fields
    score: omniguideProduct['score'],
    is_recommended: omniguideProduct['is_recommended'],
    llm_relevance: omniguideProduct['llm_relevance'],
    tag: omniguideProduct['tag'],
    url: bcProduct?.['path'] ?? bcProduct?.['url'] ?? omniguideProduct['url'] ?? omniguideProduct['path'],
    path: bcProduct?.['path'] ?? omniguideProduct['path'] ?? omniguideProduct['url'],
  };

  // Fallback: generate search URL from SKU/name
  if (!merged['url'] && !merged['path']) {
    const searchQuery = encodeURIComponent(String(merged['sku'] ?? merged['name'] ?? ''));
    merged['url'] = `/search.php?search_query=${searchQuery}`;
    merged['path'] = `/search.php?search_query=${searchQuery}`;
  }

  return merged;
}

/** Merge a Omniguide category with a BigCommerce category. */
function mergeCategory(omniguideCategory: Entity, bcCategory: Entity | undefined): Entity {
  return {
    ...omniguideCategory,
    ...bcCategory,
    tag: omniguideCategory['tag'],
    url: bcCategory?.['path'] ?? bcCategory?.['url'] ?? omniguideCategory['url'] ?? omniguideCategory['path'],
    path: bcCategory?.['path'] ?? omniguideCategory['path'] ?? omniguideCategory['url'],
  };
}

/** Build product-fallback source from unhydrated product data. */
function buildFallbackProductSource(product: Entity): { type: string; data: Entity } {
  const data = { ...product };
  if (!data['url'] && !data['path']) {
    const searchQuery = encodeURIComponent(String(data['sku'] ?? data['name'] ?? ''));
    data['url'] = `/search.php?search_query=${searchQuery}`;
    data['path'] = `/search.php?search_query=${searchQuery}`;
  }
  return { type: 'product', data };
}

// ── Hook ───────────────────────────────────────────────────────────

export function useBCChatHydration({
  storefrontToken,
  setMessages,
  currentMessageIdRef,
  trackRecommendationProvided,
  api,
}: UseBCChatHydrationOptions): ChatHydration {

  /**
   * Hydrate products with BigCommerce data (images, URLs, prices)
   */
  const hydrateProducts = useCallback(async (products: unknown[]) => {
    const items = products as Entity[];
    if (!items || items.length === 0) return;

    const messageId = currentMessageIdRef.current;
    if (!messageId) return;

    setMessages(prev => prev.map(m =>
      m.id === messageId ? { ...m, isLoadingSources: true } as ChatMessage : m
    ));

    try {
      const hydratedProducts = await api.fetchProductData(items, storefrontToken);

      const productSources = items.map(omniguideProduct => ({
        type: 'product',
        data: mergeProduct(omniguideProduct, matchById(omniguideProduct, hydratedProducts)),
      }));

      setMessages(prev => prev.map(m =>
        m.id === messageId
          ? { ...m, sources: [...(m.sources ?? []), ...productSources], isLoadingSources: false } as ChatMessage
          : m
      ));

      if (trackRecommendationProvided) {
        trackRecommendationProvided({
          messageId,
          recommendationType: 'products',
          itemCount: items.length,
          context: getPageContext(),
        });
      }
    } catch (err) {
      log.error('Failed to hydrate products:', err);

      const productSources = items.map(buildFallbackProductSource);

      setMessages(prev => prev.map(m =>
        m.id === messageId
          ? { ...m, sources: [...(m.sources ?? []), ...productSources], isLoadingSources: false } as ChatMessage
          : m
      ));
    }
  }, [storefrontToken, setMessages, currentMessageIdRef, trackRecommendationProvided, api]);

  /**
   * Hydrate categories with BigCommerce data (URLs, images)
   */
  const hydrateCategories = useCallback(async (categories: unknown[]) => {
    const items = categories as Entity[];
    if (!items || items.length === 0) return;

    const messageId = currentMessageIdRef.current;
    if (!messageId) return;

    setMessages(prev => prev.map(m =>
      m.id === messageId ? { ...m, isLoadingSources: true } as ChatMessage : m
    ));

    try {
      const hydratedCategories = await api.fetchCategoryData(items, storefrontToken);

      const categorySources = items.map(omniguideCategory => ({
        type: 'category',
        data: mergeCategory(omniguideCategory, matchById(omniguideCategory, hydratedCategories)),
      }));

      setMessages(prev => prev.map(m =>
        m.id === messageId
          ? { ...m, sources: [...(m.sources ?? []), ...categorySources], isLoadingSources: false } as ChatMessage
          : m
      ));

      if (trackRecommendationProvided) {
        trackRecommendationProvided({
          messageId,
          recommendationType: 'categories',
          itemCount: items.length,
          context: getPageContext(),
        });
      }
    } catch (err) {
      log.error('Failed to hydrate categories:', err);

      const categorySources = items.map(category => ({ type: 'category', data: category }));
      setMessages(prev => prev.map(m =>
        m.id === messageId
          ? { ...m, sources: [...(m.sources ?? []), ...categorySources], isLoadingSources: false } as ChatMessage
          : m
      ));
    }
  }, [storefrontToken, setMessages, currentMessageIdRef, trackRecommendationProvided, api]);

  /**
   * Hydrate sources (mixed products, categories, content in parallel)
   */
  const hydrateSources = useCallback(async (apiSources: unknown[]) => {
    const items = apiSources as Entity[];
    if (!items || items.length === 0) return;

    const messageId = currentMessageIdRef.current;
    if (!messageId) return;

    setMessages(prev => prev.map(m =>
      m.id === messageId ? { ...m, isLoadingSources: true, pendingSources: items } as ChatMessage : m
    ));

    try {
      const productData = items.filter(s => s['type'] === 'product');
      const categoryData = items.filter(s => s['type'] === 'category');
      const contentDocuments = items.filter(s => s['type'] === 'content');

      const [products, categories, content] = await Promise.all([
        productData.length > 0 ? api.fetchProductData(productData, storefrontToken) : [],
        categoryData.length > 0 ? api.fetchCategoryData(categoryData, storefrontToken) : [],
        contentDocuments.length > 0 ? api.fetchContentData(contentDocuments) : [],
      ]);

      const finalSources = items.map(source => {
        const id = parseEntityId(source);
        switch (source['type']) {
          case 'product': {
            const product = products.find(p =>
              p['entityId'] === id || p['id'] === id || parseInt(String(p['id']), 10) === id
            );
            return product ? { type: 'product', data: product } : null;
          }
          case 'category': {
            const category = categories.find(c =>
              c['entityId'] === id || c['id'] === id || parseInt(String(c['id']), 10) === id
            );
            return category ? { type: 'category', data: category } : null;
          }
          case 'content': {
            const wpcontent = content.find(c => c['id'] === id);
            return wpcontent ? { type: 'content', data: wpcontent } : null;
          }
          default:
            return null;
        }
      }).filter(Boolean);

      setMessages(prev => prev.map(m =>
        m.id === messageId
          ? { ...m, sources: [...(m.sources ?? []), ...finalSources], isLoadingSources: false } as ChatMessage
          : m
      ));
    } catch (err) {
      log.error('Failed to hydrate sources:', err);
      setMessages(prev => prev.map(m =>
        m.id === messageId ? { ...m, isLoadingSources: false } as ChatMessage : m
      ));
    }
  }, [storefrontToken, setMessages, currentMessageIdRef, api]);

  /**
   * Handle documentation/content — transforms and adds to sources
   */
  const hydrateDocumentation = useCallback((content: unknown[]) => {
    const messageId = currentMessageIdRef.current;
    const docs = content as Entity[];
    if (!messageId || !docs || !Array.isArray(docs)) return;

    const contentSources = filterEmptyContent(docs.map(doc => ({
      type: 'content' as const,
      data: {
        id: doc['id'] as string | number | undefined,
        name: ((doc['title'] ?? doc['name'] ?? '') as string),
        url: doc['url'] as string,
        summary: ((doc['summary'] ?? '') as string),
        image: doc['image']
          ? { url: doc['image'], altText: ((doc['title'] ?? doc['name'] ?? '') as string) }
          : null,
      },
    })) as SourceItem[]);

    setMessages(prev => prev.map(m =>
      m.id === messageId
        ? { ...m, sources: [...(m.sources ?? []), ...contentSources], isLoadingSources: false } as ChatMessage
        : m
    ));

    if (trackRecommendationProvided) {
      trackRecommendationProvided({
        messageId,
        recommendationType: 'content',
        itemCount: docs.length,
        context: 'search',
      });
    }
  }, [setMessages, currentMessageIdRef, trackRecommendationProvided]);

  return {
    hydrateProducts,
    hydrateCategories,
    hydrateSources,
    hydrateDocumentation,
  };
}
