import React, { useState, useRef, useEffect } from 'react';
import { SearchPrivacySettings } from './SearchPrivacySettings.js';
import type { SearchPrivacySettingsProps } from './SearchPrivacySettings.js';
import { useCountdown } from '../../hooks/useCountdown.js';

const MAX_INPUT_LENGTH = 200;
const MAX_INPUT_ERROR_MSG = `Maximum ${MAX_INPUT_LENGTH} characters allowed`;

export interface SearchChatInputProps {
    onSendMessage: (content: string) => void;
    isLoading?: boolean;
    isMobile?: boolean;
    isCategory?: boolean;
    isCollapsed?: boolean;
    onCollapseToggle?: () => void;
    onResetChat?: () => void;
    autoFocusAfterSend?: boolean;
    variant?: 'search' | 'category';
    privacySettingsProps?: Omit<SearchPrivacySettingsProps, 'isMobile' | 'onResetChat'>;
    connectionStatus?: string;
    reconnectInfo?: { attempt: number; maxAttempts: number; delayMs: number } | null;
}

export const SearchChatInput: React.FC<SearchChatInputProps> = ({
    onSendMessage,
    isLoading = false,
    isMobile = false,
    isCategory = false,
    isCollapsed = false,
    onCollapseToggle,
    onResetChat,
    autoFocusAfterSend = false,
    privacySettingsProps,
    connectionStatus,
    reconnectInfo,
}) => {
    const [input, setInput] = useState('');
    const [isInputFocused, setIsInputFocused] = useState(false);
    const [showInputLimitError, setShowInputLimitError] = useState(false);
    const inputRef = useRef<HTMLInputElement>(null);
    const prevIsLoadingRef = useRef(isLoading);

    const isConnectionDisabled = connectionStatus === 'connecting' || connectionStatus === 'reconnecting' || connectionStatus === 'disconnected';
    const isDisabled = isLoading || isConnectionDisabled;
    const countdown = useCountdown(reconnectInfo, connectionStatus === 'reconnecting');

    const getPlaceholder = () => {
        return isMobile ? 'Ask a question' : 'Ask Anything';
    };

    useEffect(() => {
        if (prevIsLoadingRef.current && !isLoading && inputRef.current && autoFocusAfterSend) {
            inputRef.current.focus({ preventScroll: true });
        }
        prevIsLoadingRef.current = isLoading;
    }, [isLoading, autoFocusAfterSend]);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        const trimmedInput = input.trim();
        if (trimmedInput && !isDisabled) {
            const messageToSend = trimmedInput;
            setInput('');
            setShowInputLimitError(false);
            if (inputRef.current) {
                inputRef.current.value = '';
            }
            onSendMessage(messageToSend);
        }
    };

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const value = e.target.value;
        setInput(value);
        setShowInputLimitError(value.length >= MAX_INPUT_LENGTH);
    };

    const handleInputPaste = (e: React.ClipboardEvent<HTMLInputElement>) => {
        const pastedText = e.clipboardData?.getData('text') || '';
        const currentValue = input;
        const target = e.target as HTMLInputElement;
        const selectionStart = target.selectionStart || 0;
        const selectionEnd = target.selectionEnd || 0;
        const resultingLength = currentValue.length - (selectionEnd - selectionStart) + pastedText.length;
        if (resultingLength > MAX_INPUT_LENGTH) {
            setShowInputLimitError(true);
        }
    };

    const handleFocus = () => {
        setIsInputFocused(true);
        if (isCollapsed && onCollapseToggle) {
            onCollapseToggle();
        }
    };

    const inputId = isMobile ? 'chat-input-mobile' : 'chat-input';
    const errorId = isMobile ? 'chat-input-error-mobile' : 'chat-input-error';

    if (isMobile) {
        return (
            <div className="omniguide-chat__mobile-input">
                <form
                    onSubmit={handleSubmit}
                    className="omniguide-chat__mobile-input-form"
                    role="search"
                    aria-label="Ask a question"
                >
                    <label htmlFor={inputId} className="sr-only">Type your question</label>
                    <input
                        id={inputId}
                        ref={inputRef}
                        type="text"
                        value={input}
                        onChange={handleInputChange}
                        onPaste={handleInputPaste}
                        placeholder={getPlaceholder()}
                        disabled={isDisabled}
                        maxLength={MAX_INPUT_LENGTH}
                        className="omniguide-chat__mobile-input-field"
                        aria-describedby={showInputLimitError ? errorId : undefined}
                        aria-invalid={showInputLimitError}
                    />
                    <button
                        type="submit"
                        disabled={!input.trim() || isDisabled}
                        className="omniguide-chat__mobile-submit-btn"
                        data-disabled={!input.trim() || isDisabled}
                        aria-label={isLoading ? 'Sending message...' : 'Send message'}
                    >
                        GO
                    </button>
                </form>
                {showInputLimitError && (
                    <p id={errorId} className="omniguide-chat__input-error" role="alert" aria-live="assertive">
                        {MAX_INPUT_ERROR_MSG}
                    </p>
                )}
            </div>
        );
    }

    return (
        <div className={`omniguide-chat__input-container ${isCategory ? 'omniguide-chat__input-container--category' : ''} ${isCollapsed ? 'omniguide-chat__input-container--collapsed' : ''}`}>
            <form
                onSubmit={handleSubmit}
                className={`omniguide-chat__input-form ${isCategory ? 'omniguide-chat__input-form--category' : ''}`}
                data-focused={isInputFocused}
                role="search"
                aria-label="Ask a question"
            >
                <label htmlFor={inputId} className="sr-only">Type your question</label>
                <input
                    id={inputId}
                    ref={inputRef}
                    type="text"
                    value={input}
                    onChange={handleInputChange}
                    onPaste={handleInputPaste}
                    placeholder={getPlaceholder()}
                    disabled={isDisabled}
                    maxLength={MAX_INPUT_LENGTH}
                    className={`omniguide-chat__input ${isCategory ? 'omniguide-chat__input--category' : ''}`}
                    aria-describedby={showInputLimitError ? errorId : undefined}
                    aria-invalid={showInputLimitError}
                    onFocus={handleFocus}
                    onBlur={(e) => {
                        // Don't reset focus state if user clicked an interactive element
                        if (e.relatedTarget?.matches?.('a, button, input, select, textarea')) {
                            return;
                        }
                        setIsInputFocused(false);
                    }}
                />
                <button
                    type="submit"
                    disabled={!input.trim() || isDisabled}
                    className={`omniguide-chat__submit-btn ${isCategory ? 'omniguide-chat__submit-btn--category' : ''}`}
                    data-disabled={!input.trim() || isDisabled}
                    data-focused={isInputFocused}
                    aria-label={isLoading ? 'Sending message...' : 'Send message'}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" width="19" height="19" viewBox="0 0 19 19" fill="none" aria-hidden="true" focusable="false">
                        <path d="M14.2002 7.90792L7.9422 1.64991L9.5921 0L18.6667 9.07459L9.5921 18.149L7.9422 16.4991L14.2002 10.2413H0V7.90792H14.2002Z" fill="currentColor"/>
                    </svg>
                </button>
            </form>
            {showInputLimitError && (
                <p id={errorId} className="omniguide-chat__input-error" role="alert" aria-live="assertive">
                    {MAX_INPUT_ERROR_MSG}
                </p>
            )}
            {(privacySettingsProps || (isCategory && isConnectionDisabled)) && (
                <div className="omniguide-chat__input-footer">
                    {privacySettingsProps ? (
                        <SearchPrivacySettings
                            {...privacySettingsProps}
                            isMobile={false}
                            onResetChat={onResetChat}
                        />
                    ) : <div />}
                    {isCategory && isConnectionDisabled && (
                        <span className="omniguide-chat__input-status">
                            {connectionStatus === 'disconnected'
                                ? 'Unable to connect'
                                : connectionStatus === 'reconnecting' && reconnectInfo && reconnectInfo.attempt >= 2
                                    ? countdown !== null && countdown > 0
                                        ? `Next try in ${countdown}s (${reconnectInfo.attempt}/${reconnectInfo.maxAttempts})`
                                        : <>Reconnecting<span className="omniguide-chat__connecting-dots"><span>.</span><span>.</span><span>.</span></span> ({reconnectInfo.attempt}/{reconnectInfo.maxAttempts})</>
                                    : <>Connecting<span className="omniguide-chat__connecting-dots"><span>.</span><span>.</span><span>.</span></span></>}
                        </span>
                    )}
                </div>
            )}
        </div>
    );
};
