/**
 * Platform adapter interface and utilities
 *
 * Defines the contract between Omniguide components and the underlying
 * e-commerce platform. Components call these methods instead of
 * accessing platform globals directly.
 */

import type {
  PlatformAdapter,
  OmniguideProduct,
  OmniguideCategory,
  HydratedProduct,
  HydratedCategory,
} from './types.js';
import { PlatformNotInitializedError } from './errors.js';
import { logger } from './logger.js';

/**
 * No-op platform adapter (returns null/empty for all methods)
 * Used as fallback when no platform is initialized
 */
export const NullPlatformAdapter: PlatformAdapter = {
  getPlatformName: () => 'null',
  isInitialized: () => false,
  getProductSku: () => null,
  getCredentials: () => ({}),
  hydrateProducts: async (products) => products as HydratedProduct[],
  hydrateCategories: async (categories) => categories as HydratedCategory[],
};

/**
 * Platform adapter registry
 * Allows runtime switching of platform adapters
 */
class PlatformAdapterRegistry {
  private adapter: PlatformAdapter = NullPlatformAdapter;

  /**
   * Register a platform adapter
   */
  register(adapter: PlatformAdapter): void {
    this.adapter = adapter;
  }

  /**
   * Get the current platform adapter
   */
  get(): PlatformAdapter {
    return this.adapter;
  }

  /**
   * Check if a real adapter is registered
   */
  isInitialized(): boolean {
    return this.adapter !== NullPlatformAdapter && this.adapter.isInitialized();
  }

  /**
   * Reset to null adapter
   */
  reset(): void {
    this.adapter = NullPlatformAdapter;
  }
}

/**
 * Global platform adapter registry instance
 */
export const platformRegistry = new PlatformAdapterRegistry();

/**
 * Helper function to get platform adapter with initialization check
 */
export function getPlatformAdapter(): PlatformAdapter {
  const adapter = platformRegistry.get();
  if (!adapter.isInitialized()) {
    logger.warn('Platform adapter not initialized');
  }
  return adapter;
}

/**
 * Helper function to require initialized platform adapter
 * Throws if not initialized
 */
export function requirePlatformAdapter(): PlatformAdapter {
  const adapter = platformRegistry.get();
  if (!adapter.isInitialized()) {
    throw new PlatformNotInitializedError(adapter.getPlatformName());
  }
  return adapter;
}

/**
 * Create a platform adapter from partial implementation
 * Fills in missing methods with no-op implementations
 */
export function createPlatformAdapter(
  partial: Partial<PlatformAdapter> & { getPlatformName: () => string }
): PlatformAdapter {
  return {
    getPlatformName: partial.getPlatformName,
    isInitialized: partial.isInitialized ?? (() => true),
    getProductSku: partial.getProductSku ?? (() => null),
    getCredentials: partial.getCredentials ?? (() => ({})),
    hydrateProducts: partial.hydrateProducts ?? (async (products) => products as HydratedProduct[]),
    hydrateCategories: partial.hydrateCategories ?? (async (categories) => categories as HydratedCategory[]),
  };
}
