import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useProductUrlFetching } from '../../hooks/useProductUrlFetching.js';
import { useChatNavigation } from '../../hooks/useChatNavigation.js';
import { useComponent } from '../../hooks/useComponent.js';
import { SearchCollapseToggleIcon } from './SearchIcons.js';
import { SearchNavigationButtons } from './SearchNavigationButtons.js';
import { SearchEmptyState as DefaultSearchEmptyState } from './SearchEmptyState.js';
import { SearchConnectionError as DefaultSearchConnectionError } from './SearchConnectionError.js';
import { SearchConnectionBanner as DefaultSearchConnectionBanner } from './SearchConnectionBanner.js';
import { SearchThinkingIndicator } from './SearchThinkingIndicator.js';
import { SearchQAMessage as DefaultSearchQAMessage } from './SearchQAMessage.js';
import { SearchChatInput } from './SearchChatInput.js';
import type { SearchPrivacySettingsProps } from './SearchPrivacySettings.js';
import type { ChatMessage } from '../../types.js';
import { createScopedLogger } from '@swiftotter/omniguide-core';

const log = createScopedLogger('ScrollTracking');
const CHAT_PROMPT_TEXT = 'Ask a question.';

export interface SearchChatPanelProps {
    messages: ChatMessage[];
    onSendMessage: (content: string) => void;
    isMobile?: boolean;
    isOpen?: boolean;
    isCollapsed?: boolean;
    isLoading?: boolean;
    pipelineStatus?: string;
    onIntentAnswer?: (answerText: string, answerId: string | number, options?: Record<string, unknown>) => void;
    onCustomIntentAnswer?: (customText: string) => void;
    onClarificationAnswer?: (answerText: string, optionId: string | number, paramName: string) => void;
    onCustomClarificationAnswer?: (customText: string) => void;
    onCollapseToggle?: () => void;
    onResetChat?: () => void;
    variant?: 'search' | 'category';
    suggestedQuestions?: string[];
    seedQuestions?: string[];
    welcomeText?: string;
    currentMessageIndex?: number;
    onMessageIndexChange?: (index: number) => void;
    isCompactMode?: boolean;
    fetchProductUrls?: (skus: string[]) => Promise<Record<string, string>>;
    conversationId?: string;
    FeedbackWidgetComponent?: React.ComponentType<{
        entityId: string;
        entityType: string;
        context: Record<string, unknown>;
    }>;
    privacySettingsProps?: Omit<SearchPrivacySettingsProps, 'isMobile' | 'onResetChat'>;
    defaultSearchExamples?: string[];
    connectionStatus?: string;
    onRetryConnection?: () => void;
    reconnectInfo?: { attempt: number; maxAttempts: number; delayMs: number } | null;
    onScrollForMoreTapped?: (messageId: string) => void;
    onScrollStarted?: (messageId: string) => void;
}

export const SearchChatPanel: React.FC<SearchChatPanelProps> = ({
    messages,
    onSendMessage,
    isMobile = false,
    isCollapsed = false,
    isLoading = false,
    pipelineStatus = 'idle',
    onIntentAnswer,
    onCustomIntentAnswer,
    onClarificationAnswer,
    onCustomClarificationAnswer,
    onCollapseToggle,
    onResetChat,
    variant = 'search',
    suggestedQuestions = [],
    seedQuestions = [],
    welcomeText = '',
    currentMessageIndex: controlledIndex,
    onMessageIndexChange,
    isCompactMode = false,
    fetchProductUrls,
    conversationId,
    FeedbackWidgetComponent,
    privacySettingsProps,
    defaultSearchExamples,
    connectionStatus,
    onRetryConnection,
    reconnectInfo,
    onScrollForMoreTapped,
    onScrollStarted,
}) => {
    const SearchEmptyState = useComponent('SearchEmptyState', DefaultSearchEmptyState);
    const SearchQAMessage = useComponent('SearchQAMessage', DefaultSearchQAMessage);
    const SearchConnectionError = useComponent('SearchConnectionError', DefaultSearchConnectionError);
    const SearchConnectionBanner = useComponent('SearchConnectionBanner', DefaultSearchConnectionBanner);

    const isConnectionDisabled = connectionStatus === 'connecting' || connectionStatus === 'reconnecting' || connectionStatus === 'disconnected';

    const [selectedSuggestions, setSelectedSuggestions] = useState<string[]>([]);
    const [hasMoreToScroll, setHasMoreToScroll] = useState(false);
    const [hasUserScrolled, setHasUserScrolled] = useState(false);

    const chatPanelRef = useRef<HTMLDivElement>(null);
    const messagesContainerRef = useRef<HTMLDivElement>(null);
    const scrollTrackedRef = useRef<Set<string>>(new Set());

    const { productUrls } = useProductUrlFetching({ messages, fetchProductUrls });

    const {
        qaPairs,
        currentMessageIndex,
        canGoUp,
        canGoDown,
        handleNavigateUp,
        handleNavigateDown,
    } = useChatNavigation({
        messages,
        variant,
        controlledIndex,
        onMessageIndexChange,
        chatPanelRef,
    });

    // Current answer's messageId for scroll tracking
    const currentPair = qaPairs[currentMessageIndex];
    const currentMessageId = currentPair?.assistantMessage?.id ?? currentPair?.userMessage?.id ?? '';

    // Stable ref for onScrollStarted to avoid re-attaching scroll listener
    const onScrollStartedRef = useRef(onScrollStarted);
    onScrollStartedRef.current = onScrollStarted;

    // Mobile scroll indicator
    useEffect(() => {
        if (!isMobile || !messagesContainerRef.current) return;

        const container = messagesContainerRef.current;
        const msgId = currentMessageId;

        const checkScrollable = () => {
            const isScrollable = container.scrollHeight > container.clientHeight;
            const isAtBottom = container.scrollHeight - container.scrollTop - container.clientHeight < 20;
            setHasMoreToScroll(isScrollable && !isAtBottom);
        };

        const handleScroll = () => {
            checkScrollable();
            if (container.scrollTop > 0) {
                setHasUserScrolled(true);

                // AC 2-3: Fire onScrollStarted once per answer
                if (msgId && !scrollTrackedRef.current.has(msgId)) {
                    const minScroll = Math.max(30, container.scrollHeight * 0.05);
                    log.debug('Scroll detected:', { msgId, scrollTop: container.scrollTop, minScroll, scrollHeight: container.scrollHeight });
                    if (container.scrollTop >= minScroll) {
                        scrollTrackedRef.current.add(msgId);
                        log.debug('Firing onScrollStarted for message:', msgId);
                        onScrollStartedRef.current?.(msgId);
                    }
                }
            }
        };

        checkScrollable();
        setHasUserScrolled(false);

        container.addEventListener('scroll', handleScroll, { passive: true });
        const observer = new ResizeObserver(checkScrollable);
        observer.observe(container);

        return () => {
            container.removeEventListener('scroll', handleScroll);
            observer.disconnect();
        };
    }, [isMobile, messages, currentMessageIndex, isCollapsed, currentMessageId]);

    // AC 1: Handle click/tap on "Scroll for more" indicator
    const handleScrollIndicatorClick = useCallback(() => {
        if (currentMessageId && onScrollForMoreTapped) {
            log.debug('Scroll indicator tapped for message:', currentMessageId);
            onScrollForMoreTapped(currentMessageId);
        }
    }, [currentMessageId, onScrollForMoreTapped]);

    const handleExampleClick = (example: string) => {
        onSendMessage(example);
    };

    const handleSuggestionClick = (suggestion: string) => {
        setSelectedSuggestions(prev => [...prev, suggestion]);
        onSendMessage(suggestion);
    };

    const handleIntentAnswer = (answerText: string, answerId: string | number, options: Record<string, unknown> = {}) => {
        if (onIntentAnswer) onIntentAnswer(answerText, answerId, options);
    };

    const handleCustomIntentAnswer = (customText: string) => {
        if (onCustomIntentAnswer) {
            onCustomIntentAnswer(customText);
        } else {
            onSendMessage(customText);
        }
    };

    const handleClarificationAnswer = (answerText: string, optionId: string | number, paramName: string) => {
        if (onClarificationAnswer) onClarificationAnswer(answerText, optionId, paramName);
    };

    const handleCustomClarificationAnswer = (customText: string) => {
        if (onCustomClarificationAnswer) {
            onCustomClarificationAnswer(customText);
        } else {
            onSendMessage(customText);
        }
    };

    const renderMessages = () => {
        if (qaPairs.length === 0) return null;

        const pair = qaPairs[currentMessageIndex];
        if (!pair) return null;

        const key = pair.type === 'thinking' ? pair.id : pair.userMessage?.id;
        const isLatest = currentMessageIndex === qaPairs.length - 1;

        return (
            <div key={key}>
                {pair.type === 'thinking' ? (
                    <SearchThinkingIndicator />
                ) : pair.userMessage ? (
                    <SearchQAMessage
                        userMessage={pair.userMessage as { id: string; content: string }}
                        assistantMessage={pair.assistantMessage as import('./SearchQAMessage.js').SearchQAMessageProps['assistantMessage']}
                        onSuggestionClick={handleSuggestionClick}
                        onIntentAnswer={handleIntentAnswer}
                        onCustomIntentAnswer={handleCustomIntentAnswer}
                        onClarificationAnswer={handleClarificationAnswer}
                        onCustomClarificationAnswer={handleCustomClarificationAnswer}
                        selectedSuggestions={selectedSuggestions}
                        pipelineStatus={isLatest ? pipelineStatus : undefined}
                        isLoading={isLatest ? isLoading : false}
                        variant={variant}
                        productUrls={productUrls}
                        connectionStatus={isLatest ? connectionStatus : undefined}
                        reconnectInfo={isLatest ? reconnectInfo : undefined}
                        isMobile={isMobile}
                        conversationId={conversationId}
                        FeedbackWidgetComponent={FeedbackWidgetComponent}
                    />
                ) : null}
            </div>
        );
    };

    const isCategory = variant === 'category';
    const autoFocusAfterSend = !isMobile && variant === 'search';

    if (isMobile) {
        return (
            <div
                className={`omniguide-chat omniguide-chat--mobile ${isCollapsed ? 'omniguide-chat--mobile-collapsed' : ''}`}
                style={{ display: 'flex', flexDirection: 'column', flex: 1, minHeight: 0 }}
                role="region"
                aria-label="Product assistant chat"
                aria-busy={isLoading}
            >
                {isCollapsed && messages.length > 0 && (
                    <div className="omniguide-chat__mobile-nav-row">
                        <button
                            type="button"
                            className="omniguide-chat__expand-btn"
                            onClick={onCollapseToggle}
                            aria-label="Expand to see answer"
                        >
                            <span>See answer</span>
                            <svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <polyline points="6 9 12 15 18 9"></polyline>
                            </svg>
                        </button>
                    </div>
                )}

                {!isCollapsed && messages.length > 0 && (
                    <SearchNavigationButtons
                        canGoUp={canGoUp}
                        canGoDown={canGoDown}
                        onNavigateUp={handleNavigateUp}
                        onNavigateDown={handleNavigateDown}
                        currentIndex={currentMessageIndex}
                        totalCount={qaPairs.length}
                        timestamp={qaPairs[currentMessageIndex]?.userMessage?.timestamp}
                        isMobile={true}
                    />
                )}

                <div
                    className={`omniguide-chat__mobile-content ${isCollapsed ? 'omniguide-chat__mobile-content--collapsed' : ''}`}
                    ref={messagesContainerRef}
                    role="log"
                    aria-live="polite"
                    aria-label="Conversation messages"
                    aria-relevant="additions"
                    aria-hidden={isCollapsed}
                >
                    {messages.length === 0 ? (
                        connectionStatus === 'disconnected' ? (
                            <SearchConnectionError onRetry={onRetryConnection} isMobile={true} />
                        ) : (
                            <SearchEmptyState onExampleClick={handleExampleClick} isMobile={true} variant={variant} suggestedQuestions={suggestedQuestions} seedQuestions={seedQuestions} welcomeText={welcomeText} defaultSearchExamples={defaultSearchExamples} disabled={isConnectionDisabled} connectionStatus={connectionStatus} reconnectInfo={reconnectInfo} />
                        )
                    ) : (
                        <div className="omniguide-chat__mobile-full-content omniguide-chat__message-content" style={{ paddingTop: '8px', paddingBottom: '8px' }}>
                            {renderMessages()}
                            {isConnectionDisabled && (
                                <SearchConnectionBanner
                                    status={connectionStatus === 'disconnected' ? 'disconnected' : 'reconnecting'}
                                    onRetry={onRetryConnection}
                                    reconnectInfo={reconnectInfo}
                                />
                            )}
                        </div>
                    )}
                    {hasMoreToScroll && !isCollapsed && (
                        <div className="omniguide-chat__scroll-fade">
                            <div className={`omniguide-chat__scroll-indicator ${hasUserScrolled ? 'omniguide-chat__scroll-indicator--no-animate' : ''}`} onClick={handleScrollIndicatorClick} role="button" tabIndex={0} aria-label="Scroll for more content" style={{ pointerEvents: 'auto', cursor: 'pointer' }}>
                                <span>Scroll for more</span>
                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                    <polyline points="6 9 12 15 18 9"></polyline>
                                </svg>
                            </div>
                        </div>
                    )}
                </div>

                <SearchChatInput
                    onSendMessage={onSendMessage}
                    isLoading={isLoading}
                    isMobile={true}
                    isCategory={isCategory}
                    autoFocusAfterSend={false}
                    connectionStatus={connectionStatus}
                />
            </div>
        );
    }

    // Desktop layout
    const chatClassName = isCategory
        ? `omniguide-chat omniguide-chat--category ${isCollapsed ? 'omniguide-chat--collapsed' : ''}`
        : `omniguide-chat ${isCompactMode ? 'omniguide-chat--compact' : ''} ${isCollapsed ? 'omniguide-chat--collapsed' : ''}`;

    const handleChatAreaClick = (e: React.MouseEvent) => {
        const target = e.target as HTMLElement;
        if (target === chatPanelRef.current || target.classList.contains('omniguide-chat__messages')) {
            const inputEl = chatPanelRef.current?.querySelector('#chat-input') as HTMLElement | null;
            inputEl?.focus({ preventScroll: true });
        }
    };

    return (
        <div
            ref={chatPanelRef}
            className={chatClassName}
            onClick={handleChatAreaClick}
            role="region"
            aria-label="Product assistant chat"
            aria-busy={isLoading}
        >
            {!isCollapsed && onCollapseToggle && isCategory && (
                <div
                    className="omniguide-chat__header omniguide-chat__header--collapsed"
                    style={{ borderBottom: '1px solid var(--omniguide-border-lighter)' }}
                    role="region"
                    aria-label="Ask a question section"
                >
                    <h3 className="omniguide-chat__header-title omniguide-chat__header-title--category">
                        {CHAT_PROMPT_TEXT}
                    </h3>
                    <button
                        type="button"
                        className="omniguide-chat__collapse-btn"
                        onClick={onCollapseToggle}
                        aria-label="Collapse question suggestions"
                        aria-expanded="true"
                    >
                        <SearchCollapseToggleIcon isCollapsed={false} />
                    </button>
                </div>
            )}

            {!isCollapsed && messages.length > 0 && (
                <SearchNavigationButtons
                    canGoUp={canGoUp}
                    canGoDown={canGoDown}
                    onNavigateUp={handleNavigateUp}
                    onNavigateDown={handleNavigateDown}
                    currentIndex={currentMessageIndex}
                    totalCount={qaPairs.length}
                    timestamp={qaPairs[currentMessageIndex]?.userMessage?.timestamp}
                    isMobile={false}
                />
            )}

            {!isCollapsed && (
                <div
                    className={`omniguide-chat__messages ${isCategory ? 'omniguide-chat__messages--category' : ''}`}
                    style={onCollapseToggle && isCategory ? { paddingTop: 0 } : {}}
                    ref={messagesContainerRef}
                    role="log"
                    aria-live="polite"
                    aria-label="Conversation messages"
                    aria-relevant="additions"
                >
                    {messages.length === 0 ? (
                        connectionStatus === 'disconnected' ? (
                            <SearchConnectionError onRetry={onRetryConnection} isMobile={false} />
                        ) : (
                            <SearchEmptyState onExampleClick={handleExampleClick} isMobile={false} variant={variant} suggestedQuestions={suggestedQuestions} seedQuestions={seedQuestions} welcomeText={welcomeText} hideTitle={!!onCollapseToggle} defaultSearchExamples={defaultSearchExamples} disabled={isConnectionDisabled} connectionStatus={connectionStatus} reconnectInfo={reconnectInfo} />
                        )
                    ) : (
                        <div className={`omniguide-chat__message-content${isCategory ? ' omniguide-chat__message-content--category' : ''}`}>
                            {renderMessages()}
                            {isConnectionDisabled && (
                                <SearchConnectionBanner
                                    status={connectionStatus === 'disconnected' ? 'disconnected' : 'reconnecting'}
                                    onRetry={onRetryConnection}
                                    reconnectInfo={reconnectInfo}
                                />
                            )}
                        </div>
                    )}
                </div>
            )}

            <SearchChatInput
                onSendMessage={onSendMessage}
                isLoading={isLoading}
                isMobile={false}
                isCategory={isCategory}
                isCollapsed={isCollapsed}
                onCollapseToggle={onCollapseToggle}
                onResetChat={onResetChat}
                autoFocusAfterSend={autoFocusAfterSend}
                privacySettingsProps={privacySettingsProps}
                connectionStatus={connectionStatus}
                reconnectInfo={reconnectInfo}
            />
        </div>
    );
};
