import React, { useState } from 'react';

export interface FeedbackData {
    entity_id: string;
    entity_type: string;
    vote: number;
    comment: string;
    context: Record<string, unknown>;
}

export interface DiscoveryFeedbackWidgetProps {
    entityId: string;
    entityType: 'message' | 'product_recommendation' | 'category_recommendation';
    context?: Record<string, unknown>;
    className?: string;
    onSubmit: (data: FeedbackData) => Promise<unknown>;
    onSuccess?: () => void;
    onError?: (error: Error) => void;
    disabled?: boolean;
}

