/**
 * useAnalyticsTracking — Analytics tracking hook for BigCommerce themes.
 *
 * Ported from theme `search/hooks/useDataLayer.js`.
 * Uses DI `config.analyticsAdapter.track()` — the SDK never references
 * vendor-specific globals like `window.dataLayer` or PostHog.
 * Uses EventService from context for beacon-style server events.
 */

import { useRef, useCallback } from 'react';
import { createScopedLogger, getRegistrySessionId, getRegistryConversationId, getRegistrySessionStart, getPageContext } from '@swiftotter/omniguide-core';
import { useOmniguideContext } from '@swiftotter/omniguide-react';

const log = createScopedLogger('useAnalyticsTracking');

// ── Types ──────────────────────────────────────────────────────────

export interface UseAnalyticsTrackingOptions {
  websiteId: string;
}

export interface AnalyticsTrackingReturn {
  trackMessageSent: (data: {
    messageLength: number;
    isFollowUp: boolean;
    turnNumber: number;
    context?: string;
    messageType?: string;
  }) => void;
  trackProductClick: (data: {
    messageId: string;
    productId: string | number;
    productSku: string;
    position: number;
    queryContext: string;
  }) => void;
  trackCategoryClick: (data: {
    messageId: string;
    categoryId: string | number;
    name: string;
    url: string;
    position: number;
    queryContext: string;
  }) => void;
  trackContentClick: (data: {
    messageId: string;
    contentId: string | number;
    title: string;
    url: string;
    position: number;
    queryContext: string;
  }) => void;
  trackFeedback: (data: {
    messageId: string;
    feedbackType: string;
    turnNumber: number;
  }) => void;
  trackComponentClose: (data: {
    sessionDurationMs: number;
    totalMessages: number;
  }) => void;
  trackSearchOpened: (data: {
    source: string;
    page_type: string;
  }) => void;
  trackQuestionAnswered: (data: {
    questionId: unknown;
    questionText: string;
    answer: string;
    context: string;
  }) => void;
  trackRecommendationProvided: (data: {
    messageId: string;
    recommendationType: string;
    itemCount: number;
    context: string;
  }) => void;
  trackStartOver: (data: {
    context: string;
    messageCount: number;
  }) => void;
  trackScrollForMore: (data: { messageId: string }) => void;
  trackScrollStarted: (data: { messageId: string }) => void;
}

// ── Hook ───────────────────────────────────────────────────────────

export function useAnalyticsTracking({
  websiteId,
}: UseAnalyticsTrackingOptions): AnalyticsTrackingReturn {
  const { config, consentService } = useOmniguideContext();
  const hasProductClickRef = useRef(false);

  const canTrack = useCallback(() => {
    const hasConsent = consentService ? consentService.canSendAnalytics() : true;
    if (hasConsent) return true;
    // On localhost with debug enabled, bypass consent for testing
    if (typeof window !== 'undefined' && window.location.hostname === 'localhost') {
      try {
        if (localStorage.getItem('ai-debug') === 'true') {
          log.debug('canTrack: consent=NO but bypassed (localhost + ai-debug)');
          return true;
        }
      } catch { /* ignore */ }
    }
    return false;
  }, [consentService]);

  // Track via the DI analytics adapter (dataLayer, PostHog, etc. — host decides)
  const track = useCallback((eventName: string, payload: Record<string, unknown> = {}) => {
    if (!canTrack()) {
      log.debug('track() blocked by consent:', eventName);
      return;
    }
    if (!config.analyticsAdapter) {
      log.debug('track() no analyticsAdapter configured:', eventName);
      return;
    }

    const fullPayload = {
      timestamp: Date.now(),
      session_id: getRegistrySessionId(websiteId),
      conversation_id: getRegistryConversationId(websiteId),
      ...payload,
    };
    log.debug('track() firing:', eventName, fullPayload);
    config.analyticsAdapter.track(eventName, fullPayload);
  }, [canTrack, config.analyticsAdapter, websiteId]);

  // Journey metrics
  const getJourneyMetrics = useCallback(() => {
    const sessionStart = getRegistrySessionStart(websiteId) || Date.now();
    const timeInConversation = Math.round((Date.now() - sessionStart) / 1000);
    return {
      time_in_conversation_sec: timeInConversation,
      has_clicked_product: hasProductClickRef.current,
    };
  }, [websiteId]);

  // Build props for click-type analytics events
  const buildAnalyticsProperties = useCallback((baseProps: Record<string, unknown>) => {
    return {
      ...baseProps,
      conversation_id: getRegistryConversationId(websiteId),
      session_id: getRegistrySessionId(websiteId),
      ...getJourneyMetrics(),
    };
  }, [getJourneyMetrics, websiteId]);

  // Send beacon event via navigator.sendBeacon to the Omniguide backend
  const sendBeaconEvent = useCallback(
    (event: Record<string, unknown>) => {
      if (!canTrack()) return;

      try {
        const payload = {
          session_id: getRegistrySessionId(websiteId),
          website_code: websiteId,
          conversation_id: getRegistryConversationId(websiteId),
          message_id: (event['message_id'] as string) ?? null,
          events: [event],
          page_context: getPageContext(),
        };

        const eventUrl = `${config.apiBaseUrl}/api/v1/event`;

        if (navigator.sendBeacon) {
          const blob = new Blob([JSON.stringify(payload)], {
            type: 'application/json',
          });
          navigator.sendBeacon(eventUrl, blob);
        } else {
          fetch(eventUrl, {
            method: 'POST',
            body: JSON.stringify(payload),
            keepalive: true,
            headers: { 'Content-Type': 'application/json' },
          });
        }
      } catch (e) {
        log.error('sendBeaconEvent failed:', e);
      }
    },
    [websiteId, canTrack, config.apiBaseUrl],
  );

  // ── Tracking Functions ─────────────────────────────────────────

  const trackMessageSent = useCallback(
    ({ messageLength, isFollowUp, turnNumber, context, messageType }: {
      messageLength: number;
      isFollowUp: boolean;
      turnNumber: number;
      context?: string;
      messageType?: string;
    }) => {
      track('ai_search_message_sent', {
        message_length: messageLength,
        is_followup: isFollowUp,
        turn_number: turnNumber,
        context,
        message_type: messageType,
      });
    },
    [track],
  );

  const trackProductClick = useCallback(
    ({ messageId, productId, productSku, position, queryContext }: {
      messageId: string;
      productId: string | number;
      productSku: string;
      position: number;
      queryContext: string;
    }) => {
      hasProductClickRef.current = true;

      const event = {
        event: 'ai_search_product_click',
        message_id: messageId,
        product_id: productId,
        product_sku: productSku,
        product_position: position,
        query_context: queryContext,
        timestamp: Date.now(),
      };

      sendBeaconEvent(event);

      track('AI Search - Product Click', buildAnalyticsProperties({
        message_id: messageId,
        product_id: productId,
        product_sku: productSku,
        position,
        query: queryContext,
      }));
    },
    [sendBeaconEvent, buildAnalyticsProperties, track],
  );

  const trackCategoryClick = useCallback(
    ({ messageId, categoryId, name, url, position, queryContext }: {
      messageId: string;
      categoryId: string | number;
      name: string;
      url: string;
      position: number;
      queryContext: string;
    }) => {
      hasProductClickRef.current = true;

      const event = {
        event: 'ai_search_category_click',
        message_id: messageId,
        category_id: categoryId,
        category_name: name,
        category_url: url,
        category_position: position,
        query_context: queryContext,
        timestamp: Date.now(),
      };

      sendBeaconEvent(event);

      track('AI Search - Category Click', buildAnalyticsProperties({
        message_id: messageId,
        category_id: categoryId,
        category_name: name,
        category_url: url,
        position,
        query: queryContext,
      }));
    },
    [sendBeaconEvent, buildAnalyticsProperties, track],
  );

  const trackContentClick = useCallback(
    ({ messageId, contentId, title, url, position, queryContext }: {
      messageId: string;
      contentId: string | number;
      title: string;
      url: string;
      position: number;
      queryContext: string;
    }) => {
      hasProductClickRef.current = true;

      const event = {
        event: 'ai_search_content_click',
        message_id: messageId,
        content_id: contentId,
        content_title: title,
        content_url: url,
        content_position: position,
        query_context: queryContext,
        timestamp: Date.now(),
      };

      sendBeaconEvent(event);

      track('AI Search - Content Click', buildAnalyticsProperties({
        message_id: messageId,
        content_id: contentId,
        content_title: title,
        content_url: url,
        position,
        query: queryContext,
      }));
    },
    [sendBeaconEvent, buildAnalyticsProperties, track],
  );

  const trackFeedback = useCallback(
    ({ messageId, feedbackType, turnNumber }: {
      messageId: string;
      feedbackType: string;
      turnNumber: number;
    }) => {
      track('ai_search_feedback', {
        message_id: messageId,
        feedback_type: feedbackType,
        conversation_turn: turnNumber,
      });
    },
    [track],
  );

  const trackComponentClose = useCallback(
    ({ sessionDurationMs, totalMessages }: {
      sessionDurationMs: number;
      totalMessages: number;
    }) => {
      const durationSeconds = Math.round(sessionDurationMs / 1000);

      track('ai_search_closed', {
        session_duration_ms: sessionDurationMs,
        session_duration: durationSeconds,
        message_count: totalMessages,
        product_clicked: hasProductClickRef.current,
      });

      hasProductClickRef.current = false;
    },
    [track],
  );

  const trackSearchOpened = useCallback(
    ({ source, page_type }: { source: string; page_type: string }) => {
      track('ai_search_opened', { source, page_type });
    },
    [track],
  );

  const trackQuestionAnswered = useCallback(
    ({ questionId, questionText, answer, context }: {
      questionId: unknown;
      questionText: string;
      answer: string;
      context: string;
    }) => {
      track('ai_search_question_answered', {
        question_id: questionId,
        question_text: questionText,
        answer,
        context,
      });
    },
    [track],
  );

  const trackRecommendationProvided = useCallback(
    ({ messageId, recommendationType, itemCount, context }: {
      messageId: string;
      recommendationType: string;
      itemCount: number;
      context: string;
    }) => {
      track('ai_search_recommendation_provided', {
        message_id: messageId,
        recommendation_type: recommendationType,
        item_count: itemCount,
        context,
      });
    },
    [track],
  );

  const trackStartOver = useCallback(
    ({ context, messageCount }: { context: string; messageCount: number }) => {
      track('ai_search_start_over', { context, message_count: messageCount });
    },
    [track],
  );

  const trackScrollForMore = useCallback(
    ({ messageId }: { messageId: string }) => {
      log.debug('trackScrollForMore:', { messageId });
      track('scroll_for_more', { message_id: messageId });
    },
    [track],
  );

  const trackScrollStarted = useCallback(
    ({ messageId }: { messageId: string }) => {
      log.debug('trackScrollStarted:', { messageId });
      track('chat_with_scroll_for_more_scrolled', { message_id: messageId });
    },
    [track],
  );

  return {
    trackMessageSent,
    trackProductClick,
    trackCategoryClick,
    trackContentClick,
    trackFeedback,
    trackComponentClose,
    trackSearchOpened,
    trackQuestionAnswered,
    trackRecommendationProvided,
    trackStartOver,
    trackScrollForMore,
    trackScrollStarted,
  };
}
