import { useState, useEffect, useRef } from 'react';

interface ReconnectInfo {
    attempt: number;
    maxAttempts: number;
    delayMs: number;
}

/**
 * Countdown timer for reconnection delays.
 * Returns seconds remaining (null when not counting down).
 *
 * @param reconnectInfo - current reconnect attempt info (null when not reconnecting)
 * @param active - whether the countdown should be running (e.g. status === 'reconnecting')
 */
export function useCountdown(
    reconnectInfo: ReconnectInfo | null | undefined,
    active: boolean,
): number | null {
    const [countdown, setCountdown] = useState<number | null>(null);
    const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

    useEffect(() => {
        if (intervalRef.current) {
            clearInterval(intervalRef.current);
            intervalRef.current = null;
        }

        if (!reconnectInfo || !active) {
            setCountdown(null);
            return;
        }

        let remaining = Math.ceil(reconnectInfo.delayMs / 1000);
        setCountdown(remaining);

        intervalRef.current = setInterval(() => {
            remaining -= 1;
            if (remaining <= 0) {
                setCountdown(null);
                if (intervalRef.current) {
                    clearInterval(intervalRef.current);
                    intervalRef.current = null;
                }
            } else {
                setCountdown(remaining);
            }
        }, 1000);

        return () => {
            if (intervalRef.current) {
                clearInterval(intervalRef.current);
                intervalRef.current = null;
            }
        };
    }, [reconnectInfo, active]);

    return countdown;
}
