/**
 * Omniguide HTTP API client
 *
 * Provides HTTP requests to the Omniguide backend API.
 * Handles timeouts, retries, and error normalization.
 */

import type { APIRequestOptions, APIResponse } from './types.js';
import { APIError, APITimeoutError } from './errors.js';

/**
 * Default configuration
 */
const DEFAULT_CONFIG = {
  timeout: 10000,
  retries: 1,
  retryDelay: 1000,
} as const;

/**
 * Omniguide API client
 */
export class ApiClient {
  private baseUrl: string;
  private defaultTimeout: number;
  private defaultHeaders: Record<string, string>;

  constructor(config: {
    baseUrl: string;
    timeout?: number;
    headers?: Record<string, string>;
  }) {
    this.baseUrl = config.baseUrl.replace(/\/$/, ''); // Remove trailing slash
    this.defaultTimeout = config.timeout ?? DEFAULT_CONFIG.timeout;
    this.defaultHeaders = {
      'Content-Type': 'application/json',
      ...config.headers,
    };
  }

  /**
   * Make an HTTP request
   */
  async request<T>(
    endpoint: string,
    options: APIRequestOptions = {}
  ): Promise<APIResponse<T>> {
    const url = endpoint.startsWith('http') ? endpoint : `${this.baseUrl}${endpoint}`;
    const timeout = options.timeout ?? this.defaultTimeout;

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    try {
      const response = await fetch(url, {
        method: options.method ?? 'GET',
        headers: {
          ...this.defaultHeaders,
          ...options.headers,
        },
        body: options.body ? JSON.stringify(options.body) : undefined,
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        throw new APIError(`API request failed: ${response.statusText}`, {
          status: response.status,
          statusText: response.statusText,
          url,
        });
      }

      const data = await response.json() as T;

      return {
        data,
        status: response.status,
        headers: response.headers,
      };
    } catch (error) {
      clearTimeout(timeoutId);

      if (error instanceof APIError) {
        throw error;
      }

      if (error instanceof Error) {
        if (error.name === 'AbortError') {
          throw new APITimeoutError(url, timeout);
        }

        throw new APIError(`API request failed: ${error.message}`, {
          cause: error,
          url,
        });
      }

      throw new APIError('API request failed', { url });
    }
  }

  /**
   * GET request
   */
  async get<T>(endpoint: string, options?: Omit<APIRequestOptions, 'method' | 'body'>): Promise<APIResponse<T>> {
    return this.request<T>(endpoint, { ...options, method: 'GET' });
  }

  /**
   * POST request
   */
  async post<T>(endpoint: string, body?: unknown, options?: Omit<APIRequestOptions, 'method' | 'body'>): Promise<APIResponse<T>> {
    return this.request<T>(endpoint, { ...options, method: 'POST', body });
  }

  /**
   * PUT request
   */
  async put<T>(endpoint: string, body?: unknown, options?: Omit<APIRequestOptions, 'method' | 'body'>): Promise<APIResponse<T>> {
    return this.request<T>(endpoint, { ...options, method: 'PUT', body });
  }

  /**
   * DELETE request
   */
  async delete<T>(endpoint: string, options?: Omit<APIRequestOptions, 'method' | 'body'>): Promise<APIResponse<T>> {
    return this.request<T>(endpoint, { ...options, method: 'DELETE' });
  }

  /**
   * Update base URL
   */
  setBaseUrl(url: string): void {
    this.baseUrl = url.replace(/\/$/, '');
  }

  /**
   * Update default headers
   */
  setHeaders(headers: Record<string, string>): void {
    this.defaultHeaders = {
      ...this.defaultHeaders,
      ...headers,
    };
  }
}

/**
 * Create a ApiClient instance with retry support
 */
export function createAPIWithRetry(
  config: {
    baseUrl: string;
    timeout?: number;
    headers?: Record<string, string>;
    retries?: number;
    retryDelay?: number;
  }
): ApiClient & { requestWithRetry: <T>(endpoint: string, options?: APIRequestOptions) => Promise<APIResponse<T>> } {
  const api = new ApiClient(config);
  const retries = config.retries ?? DEFAULT_CONFIG.retries;
  const retryDelay = config.retryDelay ?? DEFAULT_CONFIG.retryDelay;

  return Object.assign(api, {
    async requestWithRetry<T>(
      endpoint: string,
      options: APIRequestOptions = {}
    ): Promise<APIResponse<T>> {
      let lastError: Error | undefined;

      for (let attempt = 0; attempt <= retries; attempt++) {
        try {
          return await api.request<T>(endpoint, options);
        } catch (error) {
          lastError = error instanceof Error ? error : new Error(String(error));

          // Don't retry on 4xx errors (client errors)
          if (error instanceof APIError && error.status && error.status >= 400 && error.status < 500) {
            throw error;
          }

          if (attempt < retries) {
            await new Promise(resolve => setTimeout(resolve, retryDelay * (attempt + 1)));
          }
        }
      }

      throw lastError ?? new APIError('Request failed after retries');
    },
  });
}
