/**
 * OmniguideProvider - React context provider for Omniguide SDK
 *
 * Provides configuration, platform adapter, and storage to all child components.
 */

import React, { createContext, useContext, useMemo } from 'react';
import {
  NullPlatformAdapter,
  LocalStorageAdapter,
  platformRegistry,
  createFeedbackAPI,
  createConsentService,
  createEventService,
  capturePageContext,
  logger,
  getRegistrySessionId,
  isPreviewMode,
  type OmniguideConfig,
  type PlatformAdapter,
  type StorageAdapter,
} from '@swiftotter/omniguide-core';
import { PreviewBanner } from '../components/PreviewBanner.js';
import type { OmniguideProviderProps, OmniguideContextValue } from '../types.js';

/**
 * Default context value (uninitialized)
 */
const defaultContextValue: OmniguideContextValue = {
  config: {
    websiteId: '',
    apiBaseUrl: '',
    aiSearchStoreUrl: '',
    features: {
      search: false,
      productFit: false,
      categoryGuide: false,
      discoveryQuestions: false,
    },
  },
  platformAdapter: NullPlatformAdapter,
  storageAdapter: new LocalStorageAdapter(),
  isInitialized: false,
  components: {},
};

/**
 * Omniguide context
 */
const OmniguideContext = createContext<OmniguideContextValue>(defaultContextValue);

/**
 * Hook to access Omniguide context
 */
export function useOmniguideContext(): OmniguideContextValue {
  const context = useContext(OmniguideContext);
  if (!context.isInitialized) {
    logger.warn('useOmniguideContext called outside of OmniguideProvider or provider not initialized');
  }
  return context;
}

/**
 * Hook to access Omniguide config
 */
export function useOmniguideConfig(): OmniguideConfig {
  return useOmniguideContext().config;
}

/**
 * Hook to access platform adapter
 */
export function usePlatformAdapter(): PlatformAdapter {
  return useOmniguideContext().platformAdapter;
}

/**
 * Hook to access storage adapter
 */
export function useStorageAdapter(): StorageAdapter {
  return useOmniguideContext().storageAdapter;
}

/**
 * OmniguideProvider component
 */
export function OmniguideProvider({
  config,
  platformAdapter,
  storageAdapter,
  components,
  children,
}: OmniguideProviderProps): JSX.Element {
  // Memoize context value including service instances
  const contextValue = useMemo<OmniguideContextValue>(() => {
    // Snapshot referrer/UTM/UA before SPA navigation can overwrite them
    capturePageContext();

    const adapter = platformAdapter ?? NullPlatformAdapter;
    const storage = storageAdapter ?? new LocalStorageAdapter();

    // Register platform adapter globally
    if (platformAdapter) {
      platformRegistry.register(platformAdapter);
    }

    // Instantiate services from config
    const consentService = config.apiBaseUrl
      ? createConsentService({ apiBaseUrl: config.apiBaseUrl })
      : undefined;

    const eventService = consentService && config.apiBaseUrl
      ? createEventService({ apiBaseUrl: config.apiBaseUrl, consentService })
      : undefined;

    const feedbackApi = config.apiBaseUrl
      ? createFeedbackAPI({
          apiBaseUrl: config.apiBaseUrl,
          websiteCode: config.websiteId,
          getSessionId: () => {
            return getRegistrySessionId(config.websiteId)
              ?? storage.getItem(config.storageKeys?.sessionId ?? 'aiSearchSessionId');
          },
        })
      : undefined;

    return {
      config,
      platformAdapter: adapter,
      storageAdapter: storage,
      isInitialized: true,
      feedbackApi,
      consentService,
      eventService,
      components: components ?? {},
    };
  }, [config, platformAdapter, storageAdapter, components]);

  const showPreviewBanner = isPreviewMode();

  return (
    <OmniguideContext.Provider value={contextValue}>
      {showPreviewBanner && <PreviewBanner />}
      {children}
    </OmniguideContext.Provider>
  );
}
