/**
 * Base WebSocket class for Omniguide features
 *
 * Handles common functionality:
 * - Connection lifecycle (connect, disconnect, reconnect)
 * - Exponential backoff reconnection
 * - Heartbeat management (optional)
 * - Session ID synchronization with server
 * - Error handling and logging
 *
 * Subclasses implement:
 * - getWebSocketUrl() - returns the feature-specific WebSocket URL
 * - handleMessage(msg) - handles feature-specific message types
 * - Feature-specific send methods
 */

import type { ConnectionStatus, WebSocketConfig, WebSocketMessage, ReconnectAttemptInfo } from './types.js';
import {
  WebSocketError,
  ConnectionTimeoutError,
  MaxReconnectsError,
} from './errors.js';
import { getCurrentPage } from './current-page.js';
import { parseAndValidateMessage } from './schemas.js';
import { logger } from './logger.js';

/**
 * Default configuration values
 */
const DEFAULT_CONFIG = {
  maxReconnectAttempts: 5,
  maxBackoffDelay: 30000,
  baseDelay: 1000,
  connectionTimeout: 10000,
  heartbeatIntervalMs: 5000,
} as const;

/**
 * Base WebSocket class for all Omniguide features
 */
export abstract class BaseWebSocket {
  protected ws: WebSocket | null = null;
  protected sessionId: string;
  protected websiteCode: string;
  protected currentPageUrl: string;

  // Callbacks
  protected onMessage: (message: WebSocketMessage) => void;
  protected onStatusChange: (status: ConnectionStatus) => void;
  protected onError: (error: Error) => void;
  protected onSessionIdUpdate?: (sessionId: string) => void;
  protected onReconnectAttempt?: (info: ReconnectAttemptInfo) => void;

  // Connection settings
  protected reconnectAttempts = 0;
  protected maxReconnectAttempts: number;
  protected maxBackoffDelay: number;
  protected baseDelay: number;
  protected connectionTimeout: number;
  protected isIntentionalClose = false;
  protected connectionPromise: Promise<void> | null = null;

  // Connection generation counter — incremented on each connect()/disconnect()
  // to invalidate stale WebSocket event handlers
  private connectionGeneration = 0;
  private rejectPendingConnection: ((error: Error) => void) | null = null;
  private reconnectTimeoutId: ReturnType<typeof setTimeout> | null = null;

  // Reconnect settings
  protected autoReconnect: boolean;

  // Heartbeat settings
  protected enableHeartbeat: boolean;
  protected heartbeatInterval: ReturnType<typeof setInterval> | null = null;
  protected heartbeatIntervalMs: number;

  // Logging
  protected logPrefix: string;

  constructor(config: WebSocketConfig) {
    this.websiteCode = config.websiteCode;
    this.sessionId = config.sessionId ?? '';
    this.currentPageUrl = getCurrentPage();

    // Callbacks
    this.onMessage = config.onMessage ?? (() => {});
    this.onStatusChange = config.onStatusChange ?? (() => {});
    this.onError = config.onError ?? (() => {});

    // Connection settings
    this.maxReconnectAttempts = config.maxReconnectAttempts ?? DEFAULT_CONFIG.maxReconnectAttempts;
    this.maxBackoffDelay = config.maxBackoffDelay ?? DEFAULT_CONFIG.maxBackoffDelay;
    this.baseDelay = DEFAULT_CONFIG.baseDelay;
    this.connectionTimeout = config.connectionTimeout ?? DEFAULT_CONFIG.connectionTimeout;

    // Reconnect settings
    this.autoReconnect = config.autoReconnect ?? true;
    this.onReconnectAttempt = config.onReconnectAttempt;

    // Heartbeat settings
    this.enableHeartbeat = config.enableHeartbeat ?? false;
    this.heartbeatIntervalMs = config.heartbeatIntervalMs ?? DEFAULT_CONFIG.heartbeatIntervalMs;

    // Logging
    this.logPrefix = config.logPrefix ?? '[BaseWebSocket]';
  }

  /**
   * Get WebSocket URL - MUST be overridden by subclass
   */
  protected abstract getWebSocketUrl(): string;

  /**
   * Handle feature-specific messages - override in subclass
   */
  protected handleMessage(msg: WebSocketMessage): void {
    this.onMessage(msg);
  }

  /**
   * Connect to WebSocket server
   *
   * Uses a generation counter to guard against disconnect-during-connect races:
   * if disconnect() is called while connecting, the pending promise is rejected
   * and all stale WebSocket event handlers become no-ops.
   */
  connect(): Promise<void> {
    if (this.connectionPromise) {
      return this.connectionPromise;
    }

    // Cancel any scheduled reconnect to prevent races when connect() is
    // called manually (e.g. "Try Again") while auto-reconnect is pending.
    this.cancelPendingReconnect();

    const generation = ++this.connectionGeneration;
    this.isIntentionalClose = false;

    this.connectionPromise = new Promise((resolve, reject) => {
      this.rejectPendingConnection = reject;

      const wsUrl = this.getWebSocketUrl();
      this.onStatusChange('connecting');

      try {
        this.ws = new WebSocket(wsUrl);
      } catch (error) {
        this.connectionPromise = null;
        this.rejectPendingConnection = null;
        this.onStatusChange('disconnected');
        logger.debug(`${this.logPrefix} Failed to create WebSocket:`, {
          url: wsUrl,
          error: error instanceof Error ? error.message : String(error),
          origin: typeof window !== 'undefined' ? window.location.origin : 'unknown',
        });
        reject(
          new WebSocketError('Failed to create WebSocket', {
            cause: error instanceof Error ? error : undefined,
            url: wsUrl,
          })
        );
        return;
      }

      const connectionTimeoutId = setTimeout(() => {
        if (this.ws && this.ws.readyState === WebSocket.CONNECTING) {
          this.ws.close();
          if (generation === this.connectionGeneration) {
            this.connectionPromise = null;
            this.rejectPendingConnection = null;
          }
          reject(new ConnectionTimeoutError(wsUrl, this.connectionTimeout));
        }
      }, this.connectionTimeout);

      this.ws.onopen = () => {
        clearTimeout(connectionTimeoutId);

        // Stale connection — disconnect() was called while connecting.
        // Close the orphaned socket; the promise was already rejected by disconnect().
        if (generation !== this.connectionGeneration) {
          if (this.ws) {
            this.ws.close();
            this.ws = null;
          }
          return;
        }

        this.rejectPendingConnection = null;
        this.reconnectAttempts = 0;
        this.onStatusChange('connected');

        if (this.enableHeartbeat) {
          this.startHeartbeat();
        }

        // Small delay to ensure server has called accept() before client sends data
        setTimeout(() => {
          resolve();
        }, 50);
      };

      this.ws.onmessage = (event) => {
        // Non-Negotiable #2: Schema Validation
        // Use schema validation instead of raw JSON.parse
        const msg = parseAndValidateMessage(event.data);

        if (msg === null) {
          // Schema validation failed - already logged in parseAndValidateMessage
          // Continue without crashing (graceful degradation)
          return;
        }

        this.handleIncomingMessage(msg as WebSocketMessage);
      };

      this.ws.onclose = (event) => {
        clearTimeout(connectionTimeoutId);

        // Stale connection — skip state management
        if (generation !== this.connectionGeneration) return;

        this.connectionPromise = null;
        this.rejectPendingConnection = null;
        this.stopHeartbeat();

        const closeInfo = {
          code: event.code,
          reason: event.reason || 'No reason provided',
          wasClean: event.wasClean,
          intentional: this.isIntentionalClose,
          url: wsUrl,
        };

        if (!event.wasClean && !this.isIntentionalClose) {
          logger.warn(`${this.logPrefix} Connection closed unexpectedly:`, closeInfo);
        } else {
          logger.debug(`${this.logPrefix} Connection closed:`, closeInfo);
        }

        if (!this.isIntentionalClose) {
          if (event.code !== 1000 && event.code !== 1001) {
            const error = new WebSocketError(
              `WebSocket closed unexpectedly: ${closeInfo.reason}`,
              {
                closeCode: event.code,
                closeReason: closeInfo.reason,
                url: wsUrl,
              }
            );
            this.onError(error);
          }

          if (this.autoReconnect) {
            this.onStatusChange('reconnecting');
            this.scheduleReconnect();
          } else {
            this.onStatusChange('disconnected');
          }
        } else {
          this.onStatusChange('disconnected');
        }
      };

      this.ws.onerror = () => {
        clearTimeout(connectionTimeoutId);

        // Stale connection — skip state management
        if (generation !== this.connectionGeneration) return;

        this.connectionPromise = null;
        this.rejectPendingConnection = null;

        const diagnostics = {
          readyState: this.ws?.readyState,
          url: wsUrl,
          origin: typeof window !== 'undefined' ? window.location.origin : 'unknown',
          protocol: typeof window !== 'undefined' ? window.location.protocol : 'unknown',
          websiteCode: this.websiteCode,
          sessionId: this.sessionId ? `${this.sessionId.substring(0, 20)}...` : '(none)',
          timestamp: new Date().toISOString(),
        };

        const error = new WebSocketError('WebSocket connection error occurred', {
          readyState: this.ws?.readyState,
          url: wsUrl,
        });

        logger.error(`${this.logPrefix} WebSocket error:`, { url: wsUrl, readyState: this.ws?.readyState });
        logger.debug(`${this.logPrefix} WebSocket error diagnostics:`, diagnostics);

        this.onError(error);
        reject(error);
      };
    });

    return this.connectionPromise;
  }

  /**
   * Internal message handler - routes common messages and delegates to subclass
   */
  private handleIncomingMessage(msg: WebSocketMessage): void {
    // Handle common message types
    switch (msg.type) {
      case 'ping':
        // Heartbeat - ignore
        return;

      case 'session_id':
        // Update to canonical session ID from server
        if (typeof msg['session_id'] === 'string' && msg['session_id']) {
          this.sessionId = msg['session_id'];
          this.onSessionIdUpdate?.(msg['session_id']);
        }
        break;
    }

    // Delegate to subclass handler
    this.handleMessage(msg);
  }

  /**
   * Schedule reconnection with exponential backoff + jitter.
   * Jitter prevents thundering-herd when many clients reconnect simultaneously.
   */
  protected scheduleReconnect(): void {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      this.onStatusChange('disconnected');
      this.onError(new MaxReconnectsError(this.maxReconnectAttempts));
      return;
    }

    const exponentialDelay = this.baseDelay * Math.pow(2, this.reconnectAttempts);
    const jitter = Math.random() * this.baseDelay;
    const delay = Math.min(exponentialDelay + jitter, this.maxBackoffDelay);

    const attemptInfo: ReconnectAttemptInfo = {
      attempt: this.reconnectAttempts + 1,
      maxAttempts: this.maxReconnectAttempts,
      delayMs: Math.round(delay),
    };

    logger.debug(
      `${this.logPrefix} Reconnecting in ${attemptInfo.delayMs}ms (attempt ${attemptInfo.attempt}/${attemptInfo.maxAttempts})`
    );

    this.onReconnectAttempt?.(attemptInfo);

    this.reconnectTimeoutId = setTimeout(() => {
      this.reconnectTimeoutId = null;
      this.reconnectAttempts++;
      this.connect().catch(() => {
        // Error handled in connect()
      });
    }, delay);
  }

  /**
   * Cancel any pending reconnect timeout
   */
  private cancelPendingReconnect(): void {
    if (this.reconnectTimeoutId !== null) {
      clearTimeout(this.reconnectTimeoutId);
      this.reconnectTimeoutId = null;
    }
  }

  /**
   * Start heartbeat to keep connection alive
   */
  protected startHeartbeat(): void {
    this.stopHeartbeat();
    this.sendPing();

    this.heartbeatInterval = setInterval(() => {
      if (this.isConnected()) {
        this.sendPing();
      } else {
        this.stopHeartbeat();
      }
    }, this.heartbeatIntervalMs);
  }

  /**
   * Stop heartbeat interval
   */
  protected stopHeartbeat(): void {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
      this.heartbeatInterval = null;
    }
  }

  /**
   * Send ping message to keep connection alive
   */
  protected sendPing(): void {
    if (this.isConnected()) {
      try {
        this.ws?.send(JSON.stringify({ type: 'ping' }));
      } catch (error) {
        logger.warn(`${this.logPrefix} Failed to send ping:`, error);
      }
    }
  }

  /**
   * Send a message to the server
   */
  protected send(message: Record<string, unknown>): void {
    if (!this.isConnected()) {
      throw new WebSocketError('WebSocket not connected');
    }

    // Add common fields
    const fullMessage = {
      ...message,
      website_code: this.websiteCode,
      current_page: this.currentPageUrl,
    };

    this.ws?.send(JSON.stringify(fullMessage));
  }

  /**
   * Check if WebSocket is connected
   */
  isConnected(): boolean {
    return this.ws !== null && this.ws.readyState === WebSocket.OPEN;
  }

  /**
   * Disconnect WebSocket
   *
   * Increments the connection generation to invalidate any pending connect()
   * handlers, rejects the pending connection promise (so callers don't hang),
   * and cancels any scheduled reconnect.
   */
  disconnect(): void {
    this.isIntentionalClose = true;
    this.connectionGeneration++; // Invalidate all pending event handlers
    this.stopHeartbeat();
    this.cancelPendingReconnect();

    // Reject pending connection promise so callers' `await connect()` doesn't hang
    if (this.rejectPendingConnection) {
      const reject = this.rejectPendingConnection;
      this.rejectPendingConnection = null;
      reject(new WebSocketError('Connection aborted: disconnect() called during connect()'));
    }

    if (this.ws) {
      this.ws.close();
      this.ws = null;
    }

    this.connectionPromise = null;
    this.onStatusChange('disconnected');
  }

  /**
   * Reset connection (close and reconnect)
   */
  async reset(): Promise<void> {
    this.disconnect();
    this.isIntentionalClose = false;
    this.reconnectAttempts = 0;
    await this.connect();
  }

  /**
   * Get current session ID
   */
  getSessionId(): string {
    return this.sessionId;
  }

  /**
   * Update session ID
   */
  setSessionId(sessionId: string): void {
    this.sessionId = sessionId;
  }

  /**
   * Set callback for session ID updates
   */
  setOnSessionIdUpdate(callback: (sessionId: string) => void): void {
    this.onSessionIdUpdate = callback;
  }

  /**
   * Update current page URL (for tracking)
   */
  setCurrentPageUrl(url: string): void {
    this.currentPageUrl = url;
  }
}

/**
 * Get WebSocket base URL from REST API URL
 */
export function getWebSocketBaseUrl(apiBaseUrl: string): string {
  const isSecure = apiBaseUrl.startsWith('https') ||
    (typeof window !== 'undefined' && window.location.protocol === 'https:');
  const protocol = isSecure ? 'wss:' : 'ws:';
  const urlObj = new URL(apiBaseUrl);
  return `${protocol}//${urlObj.host}`;
}
